/**
 * Get all my chats sorted, and grouped into the right categories.
 */
export const useMyChatsTabChannels = () => {
  const { channels } = useChatState()
  const channelBuckets = useMemo(() => {
    const privateChannels = []
    const askUsAnythingChannels = []
    const vendorChannels = []
    const generalPublicChannels = []
    const rootsTechSessionChannels = []
    const rootsTechChannels = []
    const familySearchGroups = []

    const isCategoryType = (category, channel) => category.types.includes(channel.type)

    channels?.forEach((channel) => {
      if (isCategoryType(CHANNEL_CATEGORY_MAP.privateChannels, channel)) privateChannels.push(channel)
      else if (isCategoryType(CHANNEL_CATEGORY_MAP.askUsAnythingChannels, channel)) askUsAnythingChannels.push(channel)
      else if (isCategoryType(CHANNEL_CATEGORY_MAP.vendorChannels, channel)) vendorChannels.push(channel)
      else if (isCategoryType(CHANNEL_CATEGORY_MAP.attendeeCreatedChannels, channel))
        generalPublicChannels.push(channel)
      else if (isCategoryType(CHANNEL_CATEGORY_MAP.rootsTechSessionChannels, channel))
        rootsTechSessionChannels.push(channel)
      else if (isCategoryType(CHANNEL_CATEGORY_MAP.rootsTechChannels, channel)) rootsTechChannels.push(channel)
      else if (isCategoryType(CHANNEL_CATEGORY_MAP.familySearchGroups, channel)) familySearchGroups.push(channel)
    })
    return {
      privateChannels,
      vendorChannels,
      askUsAnythingChannels,
      generalPublicChannels,
      rootsTechSessionChannels,
      rootsTechChannels,
      familySearchGroups,
    }
  }, [channels])

  return channelBuckets
}

export const useFindExistingChannel = (cid) => {
  const { channels, client, isEmbedded } = useChatState()
  const [channel, setChannel] = useState(null)
  const [loadingChannel, setLoadingChannel] = useState(true)
  const chatDispatch = useChatDispatch()
  const { log } = useChatLog({ component: '[useFindExistingChannel]' })
  const { handleBasicError } = useHandleChatErrors({ log })
  const shouldFindChannel = (channel?.cid !== cid || channel?.disconnected) && !client?.wsConnection?.isDisconnected

  useEffect(() => {
    let isUnmounted = false

    const fetchChannel = async () => {
      try {
        const existingChannel = await findExistingChat(channels, client, cid, log)
        if (!isUnmounted) {
          setChannel(existingChannel)
          setLoadingChannel(false)
          const updatedChannels = updateChannelInChannels(channels, existingChannel)
          chatDispatch({ type: CHAT_ACTIONS.SET_CHANNELS, channels: updatedChannels })
        }
      } catch (err) {
        if (!isUnmounted) {
          handleBasicError(err, { moreInfo: `Problem finding existing chat. ChannelId: ${cid}` })
          setLoadingChannel(false)
        }
      }
    }

    if (shouldFindChannel && ((isEmbedded && client) || channels.length > 0)) {
      fetchChannel()
    }

    return () => {
      isUnmounted = true
    }
  }, [channels, client, cid, isEmbedded, chatDispatch, shouldFindChannel, handleBasicError, log])

  return { channel, loadingChannel }
}

export const markChannelsRead = ({ channels, handleBasicError }) => {
  channels.forEach(async (channel) => {
    try {
      if (channel?.countUnread() > 0) {
        await channel.markRead()
      }
    } catch (error) {
      handleBasicError(error, { moreInfo: `Problem marking channel as read. ChannelId: ${channel?.cid}` })
    }
  })
}

function getDMConsoleLink(channel) {
  const url = `${baseUrl}/dmconsole/chat/${channel?.cid}/messages`
  return `[DM Console](${encodeURI(url)})`
}

async function getThreadChannelInfo(pid, channels) {
  let threadChannelInfo = ''
  if (pid) {
    const threadChannel = channels.find((c) => c.id === pid)
    const threadMessages = await getRecentChannelMessages(threadChannel)
    threadChannelInfo =
      `Open thread channel CID: ${threadChannel.cid}\n` +
      `Parent channel CID: ${threadChannel.data?.fs_parent_channel_cid}\n` +
      `Parent message ID: ${pid}\n\n` +
      `5 most recent thread messages:\n${threadMessages}`
  }
  return threadChannelInfo
}

/**
 * Gets the current channel (if any) from the current route’s cid.
 * Must be used inside a <Route> with a :cid param.
 */
export function useCurrentChannel() {
  const { cid } = useParams()
  const { channels } = useChatState()
  const channel = channels?.find((c) => c.cid === cid)
  if (channel?.disconnected) {
    /* A lot of things break if we try to use a channel object that is disconnected. 
    Return undefined here so we can't try to make illegal calls on a disconnected channel object */
    return undefined
  }
  return channel
}

export const addOrRemoveChannelMembers = async ({ cid, cisIdsToAdd, cisIdsToRemove, log }) => {
  try {
    await axios.post(
      `${chatApiBase}/channels/${cid}/members`,
      { cisIdsToAdd, cisIdsToRemove },
      { headers: { 'Content-Type': 'application/json' } }
    )
  } catch (error) {
    if (log) {
      log({
        msg: `Failed to add/remove channel members. CID: ${cid}. Error: ${error}`,
        level: LOG_LEVEL.ERROR,
      })
    }
    throw error
  }
}

export const useChannelActions = ({ channel, isHeader }) => {
  const { channels, client, isEmbedded, restrictToManagedGroups, threadList } = useChatState()
  const chatDispatch = useChatDispatch()
  const { pid } = useParams()
  const [t] = useTranslation()
  const myUserId = client?.userID
  const history = useHistory()
  const isSubpage = history?.location?.pathname?.endsWith('details')
  const isCreatePage = history?.location?.pathname?.includes('chat-create')
  const displayMarkChannelRead = channel && !!getChannelUnreadCount({ channel })
  const displayLeaveChannel = canLeaveChat({ channel })
  const displayHideChannel = !displayLeaveChannel && canHideChannel(channel)
  const channelMuted = isChannelMuted(channel)
  const displayMuteChannel = canMuteChannel(channel) && !channelMuted
  const displayUnmuteChannel = canMuteChannel(channel) && channelMuted
  const displayGroupDetails = canDisplayGroupDetails(channel) && ((!isSubpage && !isCreatePage) || !isHeader)
  const displayReportAbuse = Boolean(isHeader) && !isCreatePage && canReportAbuse(channel)
  const displayBlockUser = isDirectChannel(channel) && Object.keys(channel?.state?.members || {}).length === 2
  const displayChannelActionsMenu =
    displayLeaveChannel ||
    displayMuteChannel ||
    displayUnmuteChannel ||
    displayBlockUser ||
    Boolean(isHeader) ||
    displayGroupDetails
  const displayViewHiddenChats = !restrictToManagedGroups
  const showStatusOverlay = useStatusOverlay()
  const name = getChannelName({ channel, excludeUserId: myUserId })
  const { log, track } = useChatLog({ component: '[useChannelActions]' })
  const { handleBasicError } = useHandleChatErrors({ log })

  // Remove threads whose parent channel CIDs are provided (e.g., parent channel left or hidden)
  const removeThreadsFromThreadList = ({ parentChannelCids }) => {
    const parentCidSet = new Set((parentChannelCids || []).filter(Boolean))
    if (!parentCidSet.size) return
    const threadsToRemove = threadList.filter((th) => parentCidSet.has(th.state?.getLatestValue()?.channel?.cid))
    if (!threadsToRemove.length) return
    const threadIdsToRemoveSet = new Set(threadsToRemove.map((thr) => thr.id))
    const updatedThreadList = threadList.filter((thread) => !threadIdsToRemoveSet.has(thread.id))
    chatDispatch({
      type: CHAT_ACTIONS.SET_THREAD_LIST,
      threadList: updatedThreadList,
      nonQueryableChannelIds: Array.from(parentCidSet),
    })
  }

  const markChannelRead = async () => {
    track({ link_name: `Chat:Mark Chat as Read ${channel?.type}` }, { chatChannelId: channel?.cid })
    const childThreads = await getChildThreadChannels({
      client,
      cid: channel?.cid,
      log,
    })
    const channelsToMark = [channel, ...childThreads]
    markChannelsRead({ channels: channelsToMark, handleBasicError })
  }

  const leaveChannel = async () => {
    try {
      track({ link_name: `Chat:Click Leave Chat ${channel?.type}` }, { chatChannelId: channel?.cid })

      // Embedded chat can continue to view a channel after leaving, and should still watch it
      if (!isEmbedded) await channel.stopWatching()
      // Mark the channel read to clean up Stream threads and prevent them from showing up in the thread list.
      channel.markRead()

      await addOrRemoveChannelMembers({
        cid: channel.cid,
        cisIdsToRemove: [client?.user?.fs_cis_id],
        log,
      })

      const childThreads = await getChildThreadChannels({
        client,
        cid: channel?.cid,
        log,
      })
      childThreads.forEach(async (threadChannel) => {
        try {
          await threadChannel.stopWatching()
          await addOrRemoveChannelMembers({
            cid: threadChannel?.cid,
            cisIdsToRemove: [client?.user?.fs_cis_id],
            log,
          })
        } catch (error) {
          if (log) {
            log({ msg: `Error leaving child thread when leaving a channel ${error}`, level: LOG_LEVEL.ERROR })
          }
        }
      })
      if (!isEmbedded) {
        showStatusOverlay({
          type: 'success',
          message: t('chat.channel-leave-success.message', 'You left {name}.', { name }),
          dismissable: true,
          transient: true,
        })
      }
      removeThreadsFromThreadList({ parentChannelCids: [channel?.cid] })
    } catch (e) {
      handleBasicError(e, {
        moreInfo: `problem leaving channel. ChannelId: ${channel?.cid}, User: ${client?.user?.fs_cis_id} `,
      })
    }
  }

  const muteChannel = async (silent = false) => {
    try {
      track({ link_name: `Chat:Click Mute Chat ${channel?.type}` }, { chatChannelId: channel?.cid })
      await channel.mute()
      const childThreads = await getChildThreadChannels({
        client,
        cid: channel?.cid,
        log,
      })
      childThreads.forEach((threadChannel) => {
        threadChannel.mute().catch((error) => {
          if (log) {
            log(
              { msg: `Error muting child thread ${error}`, level: LOG_LEVEL.ERROR },
              { channelId: channel?.cid, threadChannelId: threadChannel?.cid }
            )
          }
        })
      })
      if (silent !== true) {
        showStatusOverlay({
          type: 'success',
          message: t(
            'chat.channel-muted-success.message',
            '{name} was muted. To unmute this chat, click the three-dot menu button on the right side and select Unmute Chat.',
            { name }
          ),
          dismissable: true,
        })
      }
    } catch (e) {
      handleBasicError(e, { moreInfo: `problem muting channel. ChannelId: ${channel?.cid}` })
    }
  }

  const unmuteChannel = async (silent = false) => {
    try {
      track({ link_name: `Chat:Click Unmute Chat ${channel?.type}` }, { chatChannelId: channel?.cid })
      await channel.unmute()
      const childThreads = await getChildThreadChannels({
        client,
        cid: channel?.cid,
        log,
      })
      childThreads.forEach((threadChannel) => {
        threadChannel.unmute().catch((error) => {
          if (log) {
            log(
              { msg: `Error unmuting child thread ${error}`, level: LOG_LEVEL.ERROR },
              { channelId: channel?.cid, threadChannelId: threadChannel?.cid }
            )
          }
        })
      })
      if (silent !== true) {
        showStatusOverlay({
          type: 'success',
          message: t('chat.name-was-unmuted.message', '{name} was unmuted.', { name }),
          dismissable: true,
        })
        history.push(buildChatRoute(CHAT_ROUTE_KEY.CHAT, { cid: channel?.cid }))
      }
    } catch (e) {
      handleBasicError(e, { moreInfo: `Problem unmuting channel. ChannelId: ${channel?.cid}` })
    }
  }

  const hideChannel = async (silent = false) => {
    try {
      track({ link_name: `Chat:Click Hide Chat ${channel?.type}` }, { chatChannelId: channel?.cid })
      await channel.hide()
      const childThreads = await getChildThreadChannels({
        client,
        cid: channel?.cid,
        log,
      })
      childThreads.forEach((threadChannel) => {
        threadChannel.hide().catch((error) => {
          if (log) {
            log(
              { msg: `Error hiding child thread ${error}`, level: LOG_LEVEL.ERROR },
              { channelId: channel?.cid, threadChannelId: threadChannel?.cid }
            )
          }
        })
      })
      if (silent !== true) {
        showStatusOverlay({
          type: 'success',
          message: t('chat.channel-hide-success.message', '{name} was hidden.', { name }),
          dismissable: true,
          transient: true,
        })
      }
      removeThreadsFromThreadList({ parentChannelCids: [channel?.cid] })
    } catch (e) {
      handleBasicError(e, { moreInfo: `Problem hiding channel. ChannelId: ${channel?.cid}` })
    }
  }

  const getReportAbuseInfo = async () => {
    const channelInfo = getChannelInfo(channel)
    const threadChannelInfo = await getThreadChannelInfo(pid, channels)
    const dmConsoleLink = getDMConsoleLink(channel)
    const messages = await getRecentChannelMessages(channel)
    return `\n${channelInfo}\n\n5 most recent messages:\n${messages}\n\n${threadChannelInfo}\n\n${dmConsoleLink}`
  }

  return {
    displayChannelActionsMenu,
    displayMarkChannelRead,
    displayMuteChannel,
    displayUnmuteChannel,
    displayLeaveChannel,
    displayHideChannel,
    displayGroupDetails,
    displayReportAbuse,
    displayBlockUser,
    displayViewHiddenChats,
    name,
    getReportAbuseInfo,
    markChannelRead,
    muteChannel,
    unmuteChannel,
    leaveChannel,
    hideChannel,
  }
}

async function fetchSearchChatGroupSuggestions({ searchStr, client }) {
  const memberFilter = {
    name: { $autocomplete: searchStr.trim() },
    members: { $in: [client.userID] },
  }
  const publicFilter = {
    type: { $in: [CHANNEL_TYPE.FS_PUBLIC, CHANNEL_TYPE.FS_ROOTSTECH, CHANNEL_TYPE.FS_SESSION] },
    name: { $autocomplete: searchStr.trim() },
  }
  const sort = [{ last_message_at: -1 }]
  const options = { limit: 5, watch: false }
  // Splitting these queries up is more performant than combining them with an $or filter
  // Confirmed as of July 2024. Splitting the queries is around 30-50ms each, while combining them is around 900-1200ms
  // Confirmed again as of Feb 2026. The split queries take 60-90ms each. The combined query causes a Stream timeout (>10s)
  const [memberChannels, publicChannels] = await Promise.all([
    client.queryChannels(memberFilter, sort, options),
    client.queryChannels(publicFilter, sort, options),
  ])
  // De-duplicate any results
  const chatGroups = [
    ...memberChannels,
    ...publicChannels.filter((pc) => !memberChannels.find((mc) => mc.cid === pc.cid)),
  ]
  return mapChatGroupsToSuggestion({ chatGroups })
}

export async function fetchSearchChatMessageSuggestions({ searchStr, client }) {
  const filter = { members: { $in: [client.userID] }, type: { $ne: CHANNEL_TYPE.FS_THREAD } }
  const options = { limit: 10, offset: 0 }
  const query = { text: { $q: searchStr } }

  try {
    const searchResponse = await client.search(filter, query, options)
    const messages = searchResponse.results.map((result) => result.message).slice(0, 5)
    return mapChatMessagesToSuggestions({ messages, client, searchStr })
  } catch (error) {
    // Stream returns a 400 error when there are no searchable channels
    // We are swallowing this error and returning an empty array
    if (error?.status === 400) {
      return []
    }

    throw error
  }
}

function useStreamQuery(client) {
  const { log } = useChatLog({ component: '[useStreamMessageQuery]' })
  const { channels } = useChatState()
  const { handleBasicError } = useHandleChatErrors({ log })
  return useEvent(
    async (searchStr) => {
      const hasEnoughSearchChars = searchStr?.trim()?.length > 2
      const truncatedSearchStr = searchStr?.trim()?.slice(0, MAX_STREAM_SEARCH_LENGTH)
      if (hasEnoughSearchChars) {
        try {
          const [publicGroups, messages] = await Promise.all([
            fetchSearchChatGroupSuggestions({
              searchStr: truncatedSearchStr,
              client,
            }),
            channels?.length
              ? fetchSearchChatMessageSuggestions({ searchStr: truncatedSearchStr, client })
              : Promise.resolve([]),
          ])
          return { publicGroups, messages }
        } catch (err) {
          handleBasicError(err, { moreInfo: `Problem searching for chat groups. SearchStr: ${searchStr}}` })
        }
      }
      return { publicGroups: [], messages: [] }
    },
    [client, handleBasicError, channels?.length, log]
  )
}

export function navigateToChat({ channel, push, pid, mid }) {
  push(buildChatRoute(CHAT_ROUTE_KEY.CHAT, { cid: channel?.cid, pid, mid }))
}

const joinChannel = async ({ client, channel, push, mid, pid, log }) => {
  await addOrRemoveChannelMembers({ cid: channel.cid, cisIdsToAdd: [client?.user?.fs_cis_id], log })
  navigateToChat({ channel, push, mid, pid })
}

export function useOpenExistingChannel() {
  const { client } = useChatState()
  const chatDispatch = useChatDispatch()
  const chatFlags = useChatFlags()
  const { push } = useHistory()
  const userId = client?.userID
  const { log, track } = useChatLog({ component: '[useOpenExistingChannel]' })
  const { handleBasicError } = useHandleChatErrors({ log })

  return useCallback(
    async (channel, mid, pid) => {
      track({ link_name: `Chat:Click Open Chat ${channel?.type}` }, { chatChannelId: channel?.cid })
      try {
        if (isEventsChannel(channel)) {
          chatDispatch({
            type: CHAT_ACTIONS.SHOW_EVENTS,
            showEvents: true,
          })
          await setChatPreference(CHAT_PREF.SHOW_EVENT_CHATS, true)
        }

        if (pid) {
          navigateToChat({ push, channel, pid, mid })
        } else if (hasPendingInvite({ channel, userId })) {
          // leave acceptInvite in for any users who have pending invites
          track({ link_name: `Chat:Click Open Chat ${channel?.type}` }, { chatChannelId: channel?.cid })
          channel
            .acceptInvite({
              user_id: userId,
              message: {
                text: `${channel?.state?.members[userId]?.user?.name} joined the chat.`,
                fs_type: {
                  type: FS_CHAT_SYSTEM_MESSAGE_TYPE.JOINED_CHAT,
                  name: channel?.state?.members[userId]?.user?.name,
                },
                silent: true,
              },
              skip_push: true,
            })
            .then(() => navigateToChat({ channel, push, mid }))
        } else {
          // Handle edge cases. (e.g. patron has left the channel but the channel is still in the list of recent contacts)
          // Skip this check for managed (SFG) channels, since the user can't leave/join from the Chat UI
          if (!isManagedChannel(channel) && !isChannelMember({ channel, userId }) && !isHelperConnectChannel(channel)) {
            await joinChannel({ client, channel, push, chatFlags, log })
          }
          navigateToChat({ channel, push, mid })
        }
      } catch (e) {
        handleBasicError(e, { moreInfo: `Problem opening existing channel. ChannelId: ${channel?.cid}` })
      }
    },
    [userId, push, track, client, chatFlags, handleBasicError, chatDispatch, log]
  )
}

export function useOpenNewChannel() {
  const [t] = useTranslation()
  const { client } = useChatState()
  const chatFlags = useChatFlags()
  const { push } = useHistory()
  const { log } = useChatLog({ component: '[useOpenNewChannel]' })
  const showStatusOverlay = useStatusOverlay()

  return useCallback(
    async (channel, mid, pid) => {
      const cid = channel.cid

      try {
        const [newChannel] = await client.queryChannels({ cid: { $in: [cid] } })
        if (!newChannel && log) {
          log({ msg: `unable to query public chat to join! ${JSON.stringify(cid)}`, level: LOG_LEVEL.ERROR })
        }
        await joinChannel({ client, channel: newChannel, push, t, chatFlags, mid, pid, log })
      } catch (e) {
        if (log) {
          log({ msg: `unable to join the channel! ${JSON.stringify(cid)} error:${e}`, level: LOG_LEVEL.ERROR })
        }
        showStatusOverlay({
          type: 'warn',
          message: t('chat.unable-to-join.error', 'Unable to join {name}', { name: getChannelName({ channel }) }),
          dismissable: true,
        })
      }
    },
    [chatFlags, client, showStatusOverlay, push, t, log]
  )
}

export function useRedirectIfOnChannel(channel) {
  // useLocation is used here instead of useParams, because some parts of the code may not have access to any params (left panel, header, etc)
  const { pathname } = useLocation()
  const history = useHistory()
  const isOnChannel = pathname.startsWith(`/chat/${channel?.cid}`)

  return useCallback(() => {
    if (isOnChannel) {
      const redirectPath = buildChatRoute(CHAT_ROUTE_KEY.CHATS)
      history.push(redirectPath)
    }
  }, [history, isOnChannel])
}

// Returns a function that provides message, channel, and recent chat suggestions for a given inputText
export function useFetchChatSearchSuggestions() {
  const [t] = useTranslation()
  const { client } = useChatState()
  const channelBuckets = useMyChatsTabChannels()
  const streamQuery = useStreamQuery(client)

  return useEvent(
    async (inputText) => {
      const streamQuerySuggestions = await streamQuery(inputText)
      const publicGroups = streamQuerySuggestions?.publicGroups || []
      const messages = streamQuerySuggestions?.messages || []

      const filteredPrivateChannels = filterChannels(channelBuckets.privateChannels, inputText)
      const excludeUserId = client?.userID
      const profileSearchSuggestions = getProfileSearchGroupSuggestions({
        privateChannels: filteredPrivateChannels,
        excludeUserId,
        client,
      })
      const recentGroups = mapChatGroupsToSuggestion({
        chatGroups: [
          ...channelBuckets.askUsAnythingChannels,
          ...channelBuckets.vendorChannels,
          ...channelBuckets.rootsTechSessionChannels,
          ...channelBuckets.generalPublicChannels,
          ...channelBuckets.rootsTechChannels,
        ],
        group: t('chat.recent-chats.label', 'Recent Chats'),
      })

      return [
        ...messages,
        ...profileSearchSuggestions,
        ...recentGroups,
        ...publicGroups.filter((pg) => !recentGroups.find((rg) => rg.channel.cid === pg.channel.cid)),
      ]
    },
    [channelBuckets, client, streamQuery, t]
  )
}

// If the websocket was reconnected, the channel could be stuck with old data. Generate a key that could be used to force a refresh
export function useSyncStaleChannels({ channel, threadChannel }) {
  const [key, setKey] = useState(Date.now())
  const [threadKey, setThreadKey] = useState(Date.now())
  useEffect(() => {
    if (channel?.couldBeStale) {
      setKey(Date.now())
      channel.couldBeStale = false
    }
  }, [channel?.state.messages.length, channel])

  useEffect(() => {
    if (threadChannel?.couldBeStale) {
      setThreadKey(Date.now())
      threadChannel.couldBeStale = false
    }
  }, [threadChannel?.state.messages.length, threadChannel])

  return { key, threadKey }
}
