import React, { useRef, useState, Suspense, lazy } from 'react'
import {
  DialogOverlay,
  Button,
  useContainerWidth,
  Separator,
  Row,
  DialogOverlayFooter,
  useStatusOverlay,
  H6,
  Subheading,
} from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import ZionForm, { useZionForm, FormRadioGroup, FormRadio } from '@fs/zion-form'
import { useUserProfile } from '@fs/zion-user'
import { trackLink } from '@fs/zion-analytics'

const ProfilePreview = lazy(() => import('./ProfilePreview'))

/**
 * OptinForm renders a form to be used in a dialog overlay prompting users to update profile permissions.
 * @returns {JSX.Element}
 * @constructor
 * @param {Object} overlay overlay object
 * @param {String} mainMessage message displayed in form
 */

export default function ProfileOptInDialog({ overlay, onOptIn = () => {}, onOptOut = () => {} }) {
  const [t] = useTranslation()
  const atWidth = useContainerWidth()
  const formRef = useRef()
  const focusRef = useRef()
  const { userProfile, setOptInStatus } = useUserProfile()
  const showStatusOverlay = useStatusOverlay()

  const [submitLoading, setSubmitLoading] = useState(false)

  const optInText = t('profile-search.opt-in.button', 'Yes, include me in directory search results as shown.')
  const optOutText = t('profile-search-opt-out.button', 'No, I don’t want to appear in directory search results.')

  const dismissableSuccessProps = {
    message: t('profile-search.opt-in-success.message', `We'll include you in directory search results.`),
    dismissable: true,
    type: 'success',
    actionLabel: t('profile-search.profile-update.button', `Update Profile`),
    actionCallback: () => {
      window.location.assign('https://www.familysearch.org/identity/settings/profile')
    },
  }

  const postProfileData = async (formData) => {
    if (!formData) {
      return
    }
    const optedIn = formData.directoryChoice === 'optIn'
    if (optedIn) {
      onOptIn()
    }
    if (!optedIn) {
      dismissableSuccessProps.message = t(
        'profile-search.opt-out-success.message',
        `We'll leave you out of directory search results.`
      )
      onOptOut()
    }
    const response = await setOptInStatus(optedIn)
    if (response) {
      showStatusOverlay(dismissableSuccessProps)
    }
  }

  const methods = useZionForm({
    mode: 'all',
    defaultValues: { directoryChoice: 'optIn' },
    reValidateMode: 'onChange',
  })
  const {
    formState: { isValid },
  } = methods

  const handleFormSubmit = async (formData) => {
    setSubmitLoading(true)
    try {
      await postProfileData(formData)
      trackLink(null, null, 'click_action', `profile-interrupter:dismiss`)
      overlay.close()
    } catch {
      showStatusOverlay({
        message: t('profile-search.opt-in.error-message', 'Your selection could not be saved. Please try again.'),
        type: 'warning',
        dismissable: true,
      })
    } finally {
      setSubmitLoading(false)
    }
  }

  return (
    <DialogOverlay
      nonClosable
      focusRef={focusRef}
      {...overlay}
      title={t('profile-search.opt-in.heading', 'Connect with family and friends on FamilySearch')}
      as={ZionForm}
      methods={methods}
      onSubmit={handleFormSubmit}
      ref={formRef}
    >
      {userProfile && (
        <Suspense fallback="">
          <ProfilePreview userProfile={userProfile} />
        </Suspense>
      )}
      <Separator size="sm" />
      <H6>
        {t('profile-search.opt-in.directory-preference', 'Choose your Directory Preference')}
        <Subheading>
          {t('profile-search.opt-in.directory-preference.subheading', 'This can be changed later in Settings.')}
        </Subheading>
      </H6>
      <Separator size={atWidth({ sm: 'xs', md: 'sm' })} />
      <FormRadioGroup orientation="horizontal">
        <FormRadio label={optInText} value="optIn" name="directoryChoice" wrapLabel />
        <FormRadio label={optOutText} value="optOut" name="directoryChoice" wrapLabel />
      </FormRadioGroup>

      <DialogOverlayFooter>
        <Row alignX="end" alignY="middle">
          <Button
            onClick={() => {
              overlay.close()
              onOptOut()
            }}
          >
            {t('common-ui:cancel.action', 'Cancel')}
          </Button>

          <Button emphasis="high" disabled={!isValid || submitLoading} id="saveProfileButton" type="submit">
            {t('common-ui:save.action', 'Save')}
          </Button>
        </Row>
      </DialogOverlayFooter>
    </DialogOverlay>
  )
}
