import { maxRecentContactsInProfileSearch, isChannelMuted } from '../helpers/stream/streamChatHelper'
import { isDirectChannel } from '../services/fsChat/fsChatService'

/**
 * Convert channel item members into a simple array of search persons that have a cisId and isOnline values.
 */
export default function getProfileSearchPeople(conversations, excludedUsers) {
  const channelsWithSearchPeople = conversations
    .filter((conversation) => isDirectChannel(conversation))
    .filter((conversation) => !isChannelMuted(conversation))

  const profileSearchPeople = channelsWithSearchPeople.reduce((people, channel) => {
    const membersInConversation = channel?.state?.members ? Object.values(channel.state.members) : []
    const profilePeopleInConversation = membersInConversation.map((m) => {
      const cisId = m?.user?.fs_cis_id
      const isOnline = m?.user?.online
      return { cisId, isOnline }
    })

    const searchPeopleWithDuplicates = [...people, ...profilePeopleInConversation]
    const searchPeopleWithoutDuplicates = [...new Set(searchPeopleWithDuplicates.map((s) => s.cisId))].map((cisId) =>
      searchPeopleWithDuplicates.find((a) => a.cisId === cisId)
    )
    return searchPeopleWithoutDuplicates.filter(
      (p) => !(excludedUsers || []).find((excludedUser) => excludedUser.cisId === p.cisId)
    )
  }, [])

  return profileSearchPeople.slice(0, maxRecentContactsInProfileSearch)
}
