const USA_ID = 1
const CANADA_ID = 133
const debug = zionDebug('zion:profile-search')
const defaultNumberToLimitInclusions = 5

export const MAX_SEARCH_LENGTH = 128

const CONTACT_CATEGORIES = {
  // from source category
  CONTACTS: i18n.t('profile-search.contact-group.contacts', 'Contacts'),
  FH_NETWORK: i18n.t('profile-search.contact-group.fh-network', 'Family History Consultants'),
  WARD_DIRECTORY: i18n.t('profile-search.contact-group.ward-directory', 'Ward Members'),
  STAKE_DIRECTORY: i18n.t('profile-search.contact-group.stake-directory', 'Stake Members'),
  GLOBAL_DIRECTORY: i18n.t('profile-search.contact-group.global-directory', 'Global Directory'),
  HELP_CONTACTS: i18n.t('profile-search.contact-group.help-contacts', 'Helping'),
  GROUP_MEMBERS: i18n.t('profile-search.contact-group.group-member', 'Group Member'),
  // from source subcategory. Troy mentioned it may be useful just for differentiating between helper and helpee
  HELPEE: i18n.t('profile-search.contact-group.helpee', 'Helpee'),
  HELPER: i18n.t('profile-search.contact-group.helper', 'Helper'),
  FRIEND: i18n.t('profile-search.contact-group.friend', 'Friend'),
  STAKE_CONSULTANT: i18n.t('profile-search.contact-group.stake-consultant', 'Stake Consultant'),
  WARD_CONSULTANT: i18n.t('profile-search.contact-group.ward-consultant', 'Ward Consultant'),
  AREA_CONSULTANT: i18n.t('profile-search.contact-group.area-consultant', 'Area Consultant'),
}

/**
 * Validation
 */
export function warningValidate(text) {
  const isFreeFromSpecialCharactersRegex = /^[^!#$^&%*;()<>[\]=:?~|`/"\\]+$/
  if (!isFreeFromSpecialCharactersRegex.test(text) && text !== '') {
    return i18n.t('profile-search.symbols.validation', 'Cannot contain symbols.')
  }
  if (text.length > MAX_SEARCH_LENGTH) {
    return i18n.t('profile-search.max-string-length.validation', 'Cannot be more than {max} characters', {
      max: MAX_SEARCH_LENGTH,
    })
  }
  return ''
}

const formatPersonSuggestion = (person, onClick, t, addGroup) => {
  const formattedPerson = {
    // weird cases where person's name value is returning null, temporary fix so we don't reference null
    primaryText: `${person?.name?.value || person.contactId?.value || ''}`,
    secondaryText: `${person.contactId?.value || ''}`,
    tertiaryText: person.location?.country?.name?.label,
    startElement: (
      <ListItem.Avatar
        // weird cases where person's name value is returning null, temporary fix so we don't reference null
        monogram={`${person.name.value ? person.name.value[0] : person.contactId.value[0]}`}
        src={getPortraitUrl(person.cisId)}
        presence={person.isOnline ? 'online' : null}
      />
    ),
    endElement: (
      <ListItem.IconButton
        Icon={NoticeInfo}
        onClick={(evt) => {
          onClick(evt, person.cisId)
        }}
        aria-label={t('profile-search.notice-info.see-person-details', 'See Person Details')}
      />
    ),
    key: person.cisId,
  }
  if (addGroup) {
    formattedPerson.group = person.group ? person.group : t('profile-search.group-global-contacts', 'Global Contacts')
  }
  return formattedPerson
}

const getPersonNameFromUserConnections = (person) => {
  // The name that is in the sources seems more likely to be the right name
  if (person.sources[0].personName) {
    return person.sources[0].personName
  }
  if (person.name) {
    return person.name
  }
  if (person.contactId) {
    return person.contactId
  }
  return ''
}

const getContactCategoriesString = (sources) => {
  return sources
    ?.map((source) => {
      const category = source.category
      if (category === 'HELP_CONTACTS' || category === 'FH_NETWORK' || category === 'FAMILY_FEED_CONNECTIONS') {
        return CONTACT_CATEGORIES[source.subcategory] || ''
      }
      if (source.category === 'WARD_DIRECTORY' || source.category === 'STAKE_DIRECTORY') {
        return source.groupName || CONTACT_CATEGORIES[source.category]
      }
      return CONTACT_CATEGORIES[source.category]
    })
    .filter((category) => category)
    .join(', ')
}

const formatPrimaryText = (name, contactId) => {
  // only show contactId if it is different than the name
  if (name === contactId) {
    contactId = null
  }
  // primaryText format: Name (@contactId)
  return `${name}${contactId ? ` (@${contactId})` : ''}`
}

const formatPersonSuggestionForNewConnectionsData = (person, handleOpenContactOverlay, openInviteOverlay, t) => {
  const getGroup = () => {
    if (person.sources) {
      if (person.sources[0].category === 'STAKE_DIRECTORY' && person.sources[0].subcategory === 'WARD_MEMBER') {
        return CONTACT_CATEGORIES.WARD_DIRECTORY
      }
      if (person.sources[0].category === 'FAMILY_FEED_CONNECTIONS') {
        return CONTACT_CATEGORIES[person.sources[0].subcategory]
      }
      return CONTACT_CATEGORIES[person.sources[0].category]
    }
    return person?.group
  }

  const name = getPersonNameFromUserConnections(person)

  return {
    overline: person?.location,
    primaryText: formatPrimaryText(name, person?.contactId),
    secondaryText: getContactCategoriesString(person?.sources),
    displayName: name,
    group: getGroup(),
    disabled: !person.cisId,
    startElement: (
      <ListItem.Avatar
        monogram={`${name ? name[0] : person.contactId[0]}`}
        src={getPortraitUrl(person.cisId)}
        presence={person.isOnline ? 'online' : null}
      />
    ),
    endElement: person.cisId ? (
      <ListItem.IconButton
        Icon={NoticeInfo}
        onClick={(evt) => {
          handleOpenContactOverlay(evt, person.cisId)
        }}
        aria-label={t('profile-search.notice-info.see-person-details', 'See Person Details')}
      />
    ) : (
      <ListItem.IconButton
        Icon={NoticeWarning}
        onClick={openInviteOverlay}
        aria-label={t('profile-search.notice-info.see-person-details', 'See Person Details')}
      />
    ),
    key: person.cisId || person.sources[0].personRef,
  }
}

const addInclusions = (suggestionsFromDirectory, suggestionsFromCisIdInclusions, extraSuggestionsFromInclusions) => {
  let inclusions = []
  if (suggestionsFromCisIdInclusions) {
    inclusions = [...suggestionsFromCisIdInclusions]
  }
  if (extraSuggestionsFromInclusions) {
    inclusions = [...inclusions, ...extraSuggestionsFromInclusions]
  }
  return [...inclusions, ...suggestionsFromDirectory]
}

function shouldAddGroupToSuggestions(inclusions) {
  return Boolean(inclusions?.people?.length || inclusions?.suggestions?.length)
}

/**
 *  A hook that returns suggestions for Autosuggest and AdvancedSearch
 */
export function useProfileSuggestions(openContactOverlay, isAdvancedSearch, nameValue, openInviteOverlay) {
  const {
    setContactSelected,
    inclusions,
    error,
    isLoadingSuggestions,
    shouldUseUserConnections,
    countryValue,
    stateValue,
  } = useProfileContext()
  const [suggestionResults, setSuggestionResults] = useState([])
  const [formattedInclusions, setFormattedInclusions] = useState({ ...inclusions })
  const [t] = useTranslation()
  const [formattedSuggestions, setFormattedSuggestions] = useState([])
  const getNewSuggestions = useGetNewSelections(setSuggestionResults, setFormattedInclusions)
  // boolean on whether to sort the suggestions into groups or not
  const addGroup = shouldAddGroupToSuggestions(inclusions)

  const handleOpenContactOverlay = useCallback(
    (evt, cisId) => {
      debug('Opening Contact Overlay')
      setContactSelected({ cisId })
      openContactOverlay(evt)
    },
    [openContactOverlay, setContactSelected]
  )

  // get suggestions from inclusions
  const { suggestions: suggestionsFromCisIdInclusions } = usePeopleSuggestionsFromInclusions(handleOpenContactOverlay)

  // getNewSuggestions is a useCallback that updates whenever the search parameters change
  useEffect(() => {
    getNewSuggestions(nameValue, isAdvancedSearch)
  }, [getNewSuggestions, isAdvancedSearch, nameValue, countryValue, stateValue, inclusions])

  // format suggestions once they are available
  useEffect(() => {
    let suggestionsSet = suggestionResults
    if (!isAdvancedSearch) {
      suggestionsSet = suggestionResults.slice(0, 11)
    }
    const newFormattedSuggestions = suggestionsSet.map((person) => {
      if (person.fromConnectionsUrl) {
        return formatPersonSuggestionForNewConnectionsData(person, handleOpenContactOverlay, openInviteOverlay, t)
      }
      return formatPersonSuggestion(person, handleOpenContactOverlay, t, addGroup)
    })
    if (shouldUseUserConnections && !isAdvancedSearch) {
      const groupOrder = [
        CONTACT_CATEGORIES.CONTACTS,
        CONTACT_CATEGORIES.FRIEND,
        CONTACT_CATEGORIES.GROUP_MEMBERS,
        CONTACT_CATEGORIES.HELP_CONTACTS,
        CONTACT_CATEGORIES.FH_NETWORK,
        CONTACT_CATEGORIES.WARD_DIRECTORY,
        CONTACT_CATEGORIES.STAKE_DIRECTORY,
        CONTACT_CATEGORIES.GLOBAL_DIRECTORY,
      ]
      newFormattedSuggestions.sort((a, b) => {
        const indexA = groupOrder.indexOf(a.group)
        const indexB = groupOrder.indexOf(b.group)
        return indexA - indexB
      })
    }
    const newFormattedSuggestionsWithInclusions = addInclusions(
      newFormattedSuggestions,
      suggestionsFromCisIdInclusions,
      formattedInclusions?.suggestions
    )
    // We don't show inclusions in AdvancedSearch because they are already shown in the dropdown from the regular search
    // To put inclusions into AdvancedSearch, we would have to figure out a way to filter the inclusions
    setFormattedSuggestions(!isAdvancedSearch ? newFormattedSuggestionsWithInclusions : newFormattedSuggestions)
  }, [
    addGroup,
    handleOpenContactOverlay,
    isAdvancedSearch,
    suggestionResults,
    suggestionsFromCisIdInclusions,
    t,
    shouldUseUserConnections,
    formattedInclusions,
    openInviteOverlay,
  ])

  return {
    suggestionResults: formattedSuggestions,
    isLoadingSuggestions,
    error,
  }
}

function addActiveStatus(data, people) {
  const matchingPerson = people.find((e) => e.cisId === data.cisId)
  if (matchingPerson) {
    data.isOnline = matchingPerson.isOnline
  }
  return data
}

export function usePeopleSuggestionsFromInclusions(handleOpenContactOverlay) {
  const { inclusions } = useProfileContext()
  const [t] = useTranslation()
  // loop through people list, make call to get profile info for each person, turn each profile into a suggestion
  const [suggestions, setSuggestions] = useState([])
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState(false)
  const addGroup = shouldAddGroupToSuggestions(inclusions)
  const { log } = useProfileSearchLog({ component: '[usePeopleSuggestionsFromInclusions]' })

  useEffect(() => {
    let cancelled = false
    let peopleProfiles = []
    if (inclusions?.people && inclusions?.people.length > 0) {
      const { people } = inclusions
      setLoading(true)
      setError(false)

      // limit the amount of people profiles to read from the API to 5 if the caller does not specify a limit
      const limitedPeople = people.slice(0, inclusions?.maxPeople || 5)
      peopleProfiles = limitedPeople.map((person) => {
        return getProfileByCisId(person.cisId)
      })
      Promise.all(peopleProfiles)
        .then((res) => {
          if (!cancelled) {
            const formattedSuggestions = res.map((person) => {
              let data = person.data
              data = addActiveStatus(data, people)
              // add custom group
              data.group = inclusions?.group
              return formatPersonSuggestion(data, handleOpenContactOverlay, t, addGroup)
            })
            setSuggestions(formattedSuggestions)
            setLoading(false)
          }
        })
        .catch((err) => {
          setError(err)
          setLoading(false)
          const msg = `Error trying to get profile data from people in the inclusions list: ${err}`
          log({ msg, level: LOG_LEVEL.ERROR })
        })
    }
    return () => {
      cancelled = true
    }
  }, [addGroup, handleOpenContactOverlay, inclusions, t, log])
  return { suggestions, loading, error }
}

function getFullExclusionList(exclusionList, inclusionsToFilter, limitInclusionsToFilter) {
  if (inclusionsToFilter?.length > 0 && exclusionList) {
    const limitedInclusionsToFilter = inclusionsToFilter.slice(0, limitInclusionsToFilter)
    return [...limitedInclusionsToFilter, ...exclusionList]
  }
  return exclusionList
}

const filterExclusionList = (results, exclusionList, inclusions) => {
  const inclusionsToFilter = inclusions?.people
  const limitInclusionsToFilter = inclusions?.maxPeople || defaultNumberToLimitInclusions
  let fullExclusionList = exclusionList
  if (inclusionsToFilter) {
    fullExclusionList = getFullExclusionList(exclusionList, inclusionsToFilter, limitInclusionsToFilter)
  }
  if (fullExclusionList && fullExclusionList?.length > 0) {
    results = results.filter((personResult) => {
      const exclusionListedPerson = fullExclusionList.find(
        (exclusionListPerson) =>
          personResult.cisId?.toUpperCase() === exclusionListPerson.cisId?.toUpperCase() ||
          personResult.contactId?.value === exclusionListPerson.contactId
      )
      return !exclusionListedPerson
    })
  }
  return results
}

const filterExclusionListForConnectionsData = (results, exclusionList, inclusions) => {
  const inclusionsToFilter = inclusions?.people
  const limitInclusionsToFilter = inclusions?.maxPeople || defaultNumberToLimitInclusions
  let fullExclusionList = exclusionList
  if (inclusionsToFilter) {
    fullExclusionList = getFullExclusionList(exclusionList, inclusionsToFilter, limitInclusionsToFilter)
  }
  if (fullExclusionList && fullExclusionList?.length > 0) {
    results = results.filter((personResult) => {
      const exclusionListedPerson = fullExclusionList.find((exclusionListPerson) => {
        return (
          personResult.cisId?.toUpperCase() === exclusionListPerson.cisId?.toUpperCase() ||
          (exclusionListPerson.contactId && personResult.contactId === exclusionListPerson.contactId)
        )
      })
      return !exclusionListedPerson
    })
  }
  return results
}

const addInCountryName = (peopleData, countryOptions) => {
  return peopleData.map((person) => {
    if (person.location?.country.stdRepId && countryOptions?.length > 0) {
      person.location.country.name = countryOptions.find((x) => `${person.location.country.stdRepId}` === x.value)
    }
    return person
  })
}

const addInLocationNameForUserConnectionsData = async (
  peopleData,
  countryOptions,
  countryStateMapping,
  setCountryStateMapping
) => {
  try {
    const updatedMapping = { ...countryStateMapping }
    const peopleWithLocations = await Promise.all(
      peopleData.map(async (person) => {
        if (person.countryRepId) {
          if (person.stateOrProvinceRepId) {
            if (!updatedMapping[person.countryRepId]) {
              updatedMapping[person.countryRepId] = await getStatesAndProvinces(person.countryRepId)
            }
            const state = updatedMapping[person.countryRepId].find((s) => person.stateOrProvinceRepId === s.repId)
            if (state) {
              person.location = state.displayName
              return person
            }
          }
          person.location = countryOptions.find((country) => `${person.countryRepId}` === country.value).label
          return person
        }
        return person
      })
    )
    setCountryStateMapping(updatedMapping)
    return peopleWithLocations
  } catch (err) {
    console.error('Unable to get locations: ', err)
    return peopleData
  }
}

const addConnectionsAndLocationsToInclusions = (results, inclusions) => {
  return inclusions?.map((inclusion) => {
    if (inclusion.cisId) {
      const person = results.find((result) => result.cisId === inclusion.cisId)
      if (person) {
        const newInclusion = { ...inclusion }
        newInclusion.secondaryText += `, ${getContactCategoriesString(person.sources)}`
        const name = getPersonNameFromUserConnections(person)
        const contactId = person.contactId
        newInclusion.overline = person.location
        newInclusion.primaryText = formatPrimaryText(name, contactId)

        return newInclusion
      }
    }
    return inclusion
  })
}

// Debounce this outside of the useCallback to avoid a new debounced instance when the dependencies change
const debouncedGetMatchingPeople = (() => {
  const debounced = _debounce((resolve, reject, ...args) => {
    getMatchingPeople(...args)
      .then(resolve)
      .catch(reject)
  }, 500)
  return (...args) => {
    return new Promise((resolve, reject) => {
      debounced(resolve, reject, ...args)
    })
  }
})()

export function useGetNewSelections(setSuggestionResults, setFormattedInclusions) {
  const {
    setIsLoadingSuggestions,
    exclusionList,
    setError,
    countryOptions,
    countryValue,
    stateValue,
    inclusions,
    shouldUseUserConnections,
    countryStateMapping,
    setCountryStateMapping,
  } = useProfileContext()
  const { log } = useProfileSearchLog({ component: '[useGetNewSelections]' })

  return useEvent((nameValue, isAdvancedSearch) => {
    if (nameValue.length >= 2 && warningValidate(nameValue).length === 0) {
      setIsLoadingSuggestions?.(true)
      setError?.(false)
      debouncedGetMatchingPeople(nameValue, countryValue, stateValue, isAdvancedSearch, shouldUseUserConnections)
        .then(async ({ result, fromConnectionsUrl }) => {
          let transformedResults
          if (fromConnectionsUrl) {
            const resultsWithLocation = await addInLocationNameForUserConnectionsData(
              result.data.connections,
              countryOptions,
              countryStateMapping,
              setCountryStateMapping
            )

            const formattedInclusions = addConnectionsAndLocationsToInclusions(
              resultsWithLocation,
              inclusions.suggestions
            )
            setFormattedInclusions({ ...inclusions, suggestions: formattedInclusions })
            transformedResults = filterExclusionListForConnectionsData(
              resultsWithLocation,
              exclusionList,
              formattedInclusions
            )
          } else {
            setFormattedInclusions(inclusions)
            const filteredResults = filterExclusionList(result.data.results, exclusionList, inclusions)
            transformedResults = addInCountryName(filteredResults, countryOptions)
          }
          transformedResults.forEach((person) => {
            person.fromConnectionsUrl = fromConnectionsUrl
          })
          setSuggestionResults(transformedResults)
          setIsLoadingSuggestions?.(false)
        })
        .catch((err) => {
          setError?.(true)
          setIsLoadingSuggestions?.(false)
          const msg = `Something went wrong with the network. Error: ${err}`
          console.error(msg)
          log({ msg, level: LOG_LEVEL.ERROR })
        })
    } else {
      setFormattedInclusions({ ...inclusions })
      setSuggestionResults([])
    }
  })
}

export function useCountries() {
  const [countryOptions, setCountryOptions] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState()
  const { log } = useProfileSearchLog({ component: '[useCountries]' })

  // get list of countries for country select
  useEffect(() => {
    let cancelled = false
    getCountries()
      .then((res) => {
        if (res) {
          const newCountryOptions = res.map((x) => {
            return { value: `${x.repId}`, label: x.displayName }
          })
          // put the list of countries in alphabetic order
          if (!cancelled) {
            setCountryOptions(
              newCountryOptions.sort((a, b) => {
                return a.label.localeCompare(b.label)
              })
            )
            setLoading(false)
          }
        }
      })
      .catch((err) => {
        setError(err)
        const msg = `Unable to get the list of countries: ${JSON.stringify(err)}`
        log({ msg, level: LOG_LEVEL.ERROR })
      })
    return () => {
      cancelled = true
    }
  }, [log])
  return [countryOptions, loading, error]
}

/**
 * A hook that returns stateOptions to put into select boxes and canSelectState if a state can be selected
 * @param {*} countryValue the value of the state selected
 */
export function useStates(countryValue) {
  const [stateOptions, setStateOptions] = useState([])
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState()
  const getStatesAndProvincesCallback = useCallback(getStatesAndProvinces, [])
  // can only select state if US or Canada are selected
  const canSelectState = countryValue === `${USA_ID}` || countryValue === `${CANADA_ID}`
  const { log } = useProfileSearchLog({ component: '[useStates]' })

  // get list of states for state select
  useEffect(() => {
    let cancelled = false
    if (canSelectState) {
      setLoading(true)
      setError(null)
      getStatesAndProvincesCallback(countryValue)
        .then((states) => {
          if (states && !cancelled) {
            setStateOptions(
              states.map((x) => {
                return { value: `${x.repId}`, label: x.displayName }
              })
            )
            setLoading(false)
          }
        })
        .catch((err) => {
          setError(err)
          const msg = `Unable to get the list of states for the US: ${JSON.stringify(err)}`
          log({ msg, level: LOG_LEVEL.ERROR })
        })
    }
    return () => {
      cancelled = true
    }
  }, [countryValue, canSelectState, getStatesAndProvincesCallback, log])

  return [stateOptions, canSelectState, loading, error]
}
