import type { Ref } from 'react'
import React, { forwardRef, useContext } from 'react'
import { css, cx } from '@linaria/core'
import { sanitizeProps, useForwardRef } from '@fs/zion-frontend-friends'
import { useFeatureFlag } from '@fs/zion-flags'
import { linkCss } from '@fs/zion-router-base/internals-do-not-use'
import TextAndIconButton from '../TextAndIconButton'
import {
  colorCss,
  lowCss,
  highCss,
  grayHighCss,
  grayLowCss,
  highNightCss,
  lightHighCss,
  lightHighNightCss,
  grayLightHighNightCss,
  grayLightHighCss,
  grayHighNightCss,
} from '../colorStyles'
import { lowEmphasisCss, mediumEmphasisCss, highEmphasisCss } from '../emphasisStyles'
import { useTheme } from '../../theme'
import { WhiteThemeContext } from '../../theme/white-theme'
import colorThemes from '../../theme/themeSubsets'

import useSquishyButton from '../useSquishyButton'
import type { BillboardButtonProps } from '../types'
import { textBcss } from '../../typography/typographyStyles'

const buttonCss = css`
  display: flex;
  padding: 13px 20px;
  max-width: 100%;
  text-transform: uppercase;
  height: 44px;
  //This is to prevent the button from shrinking vertically when placed in a flex container
  min-height: 44px;

  // This is to line up the baseline of anchor tags with the baseline of buttons and text elements
  a& {
    vertical-align: -16px;
  }
`

const lowercasebuttonCss = css`
  display: flex;
  padding: 13px 20px;
  max-width: 100%;
  height: 44px;
  //This is to prevent the button from shrinking vertically when placed in a flex container
  min-height: 44px;

  // This is to line up the baseline of anchor tags with the baseline of buttons and text elements
  a& {
    vertical-align: -16px;
  }
`

const lowEmphasisLowercaseButtonCss = css`
  /* The following CSS is to override linkCss hover, visited, and focus states */
  &:hover,
  &:visited,
  &:visited:hover,
  &:focus-visible,
  &:focus {
    color: var(--button-text-color) !important;
  }

  // Ensure underlines from linkCss are preserved even with no-link-styles attribute
  &[no-link-styles] {
    text-decoration: underline !important;
  }
`

const lowEmphasisButtonCss = css`
  padding: 13px 12px;
  margin: 0 -12px;
  // This calculation should use 24px, but an extra pixel prevents always showing the ellipsis in Safari 14 and older
  // Revisit this when we only support iOS 15+
  max-width: calc(100% + 25px); // Need to account for the negative margins
`

/**
 * ### _A larger format version of the Button Component_
 *
 * A BillboardButton **must only be used** for pages that act as introductory experiences
 * to the user. Here are some examples:
 *
 * - Logged-out home pages
 * - Discovery experiences and activities
 * - Marketing pages
 */
const BillboardButton = forwardRef(
  (
    {
      emphasis = 'high',
      color: inputColor,
      fullWidth = false,
      children,
      disabled = false,
      ...props
    }: BillboardButtonProps,
    forwardedRef
  ) => {
    const ref = useForwardRef<HTMLElement>(forwardedRef as Ref<HTMLElement>)
    // @ts-expect-error -- TODO fix strict issue: This was grandfathered from before we adopted strict mode in typescript.
    const buttonScale = useSquishyButton(ref)
    const theme = useTheme()
    const isWhite = useContext(WhiteThemeContext)
    const color = inputColor ?? (isWhite && ['low', 'medium'].includes(emphasis) ? 'gray' : 'blue')
    const { isOn: lowercaseButton } = useFeatureFlag('frontier_zionui_lowercase_button')
    const classNames = [lowercaseButton ? lowercasebuttonCss : buttonCss, colorCss, textBcss, colorThemes[color]]

    switch (emphasis) {
      case 'low':
        classNames.push(
          lowercaseButton ? linkCss : null,
          // @ts-expect-error -- TODO fix strict issue: This was grandfathered from before we adopted strict mode in typescript.
          lowercaseButton ? lowEmphasisLowercaseButtonCss : null,
          lowEmphasisCss,
          lowEmphasisButtonCss
        )
        if (color === 'gray') {
          classNames.push(grayLowCss)
        } else {
          classNames.push(lowCss)
        }
        break
      case 'medium':
        classNames.push(mediumEmphasisCss)
        if (color === 'gray') {
          classNames.push(grayLowCss)
        } else {
          classNames.push(lowCss)
        }
        break
      case 'lightHigh':
        classNames.push(highEmphasisCss)
        if (color === 'gray') {
          classNames.push(theme === 'night' ? grayLightHighNightCss : grayLightHighCss)
        } else {
          classNames.push(theme === 'night' ? lightHighNightCss : lightHighCss)
        }
        break
      case 'high': // Fall through, this is default
      default:
        classNames.push(highEmphasisCss)
        if (color === 'gray') {
          classNames.push(theme === 'night' ? grayHighNightCss : grayHighCss)
        } else {
          classNames.push(theme === 'night' ? highNightCss : highCss)
        }
    }

    return (
      <TextAndIconButton
        {...sanitizeProps(props)}
        disabled={disabled}
        fullWidth={fullWidth && emphasis !== 'low'}
        iconSize="sm"
        className={cx(...classNames)}
        style={{ '--button-scale': buttonScale }}
        ref={ref}
      >
        {children}
      </TextAndIconButton>
    )
  }
)

export default BillboardButton
