import React, { useState } from 'react'
import {
  ListItem,
  TextField,
  Select,
  DialogOverlayFooter,
  List,
  Button,
  Grid,
  Cell,
  useContainerWidth,
  Skeleton,
  Row,
} from '@fs/zion-ui'
import { useHelpOverlay } from '@fs/zion-help-overlay'
import { SocialMenu } from '@fs/zion-social'
import { css } from '@linaria/core'
import { useTranslation } from 'react-i18next'
import { useStates, useProfileSuggestions, warningValidate, MAX_SEARCH_LENGTH } from './profileSearchHooks'
import { useProfileContext } from './ProfileSearchProvider'

export default function AdvancedSearchOverlayContent({
  overlay,
  openContactOverlay,
  onSuggestionSelected,
  initialInputValue,
}) {
  const {
    clearInputOnSelection,
    countryValue,
    setCountryValue,
    stateValue,
    setStateValue,
    countryOptions,
    optInUrl,
    shouldUseUserConnections,
  } = useProfileContext()
  const [nameValue, setNameValue] = useState(initialInputValue)
  const [t] = useTranslation()
  const [stateOptions, canSelectState, stateOptionsLoading] = useStates(countryValue)
  const { suggestionResults, isLoadingSuggestions, error } = useProfileSuggestions(
    openContactOverlay,
    true,
    nameValue,
    shouldUseUserConnections
  )
  const atWidth = useContainerWidth()
  const { handleClick } = useHelpOverlay('/help/helpcenter/article/directory-search-tips')

  const selectText = t('common-ui:select.action', 'Select')
  const searchText = t('common-ui:search.action', 'Search')
  const countryOrLocationText = t('profile-search.form.country-input', 'Country or Location')
  const stateOrProvinceText = t('profile-search.form.state-input', 'State or Province')

  function nameTextBoxSize() {
    return canSelectState ? atWidth({ default: 12, md: 6 }) : atWidth({ default: 12, md: 9 })
  }

  function handleOnClickPerson(person) {
    onSuggestionSelected?.(person)
    if (clearInputOnSelection) {
      setNameValue('')
    } else {
      setNameValue(person.primaryText)
    }
    overlay.close()
  }

  return (
    <>
      <div
        className={css`
          max-width: 900px;
          min-height: calc(100vh - 200px);
        `}
      >
        <Grid guttersY="none">
          <Cell columns={nameTextBoxSize()}>
            <TextField
              value={nameValue}
              name="name"
              onChange={(e) => setNameValue(e.target.value)}
              label={t('profile-search.form.name-input', 'Name or Contact ID')}
              placeholder={searchText}
              autoComplete="off" // prevent browser autocomplete
              maxLength={MAX_SEARCH_LENGTH}
              warningValidate={(text) => warningValidate(text)}
              data-testid="advanced-search-name"
            />
          </Cell>
          <Cell columns={atWidth({ default: 12, md: 3 })}>
            <Select
              value={countryValue}
              name="country"
              options={countryOptions}
              onChange={(e) => {
                setCountryValue(e.target.value)
                setStateValue(null)
              }}
              label={countryOrLocationText}
              placeholder={`${selectText} ${countryOrLocationText}`}
              data-testid="advanced-search-country"
            />
          </Cell>
          {canSelectState && !stateOptionsLoading && (
            <Cell columns={atWidth({ default: 12, md: 3 })}>
              <Select
                value={stateValue}
                name="state"
                options={stateOptions}
                onChange={(e) => setStateValue(e.target.value)}
                label={stateOrProvinceText}
                placeholder={`${selectText} ${stateOrProvinceText}`}
                data-testid="advanced-search-state"
              />
            </Cell>
          )}
          {canSelectState && stateOptionsLoading && <Skeleton.Button width={190} maxWidth={190} />}
        </Grid>
        <List>
          {/* Want the behavior similar to Autosuggest */}
          {isLoadingSuggestions && (
            <>
              <Skeleton.ListItem hasIcon hasSecondLine key="SKELETON_LISTITEM_1" />
              <Skeleton.ListItem hasIcon hasSecondLine key="SKELETON_LISTITEM_2" />
              <Skeleton.ListItem hasIcon hasSecondLine key="SKELETON_LISTITEM_3" />
              <Skeleton.ListItem hasIcon hasSecondLine key="SKELETON_LISTITEM_4" />
              <Skeleton.ListItem hasIcon hasSecondLine key="SKELETON_LISTITEM_5" />
              <Skeleton.ListItem hasIcon hasSecondLine key="SKELETON_LISTITEM_6" />
              <Skeleton.ListItem hasIcon hasSecondLine key="SKELETON_LISTITEM_7" />
              <Skeleton.ListItem hasIcon hasSecondLine key="SKELETON_LISTITEM_8" />
            </>
          )}
          {!isLoadingSuggestions && suggestionResults.length === 0 && (
            <ListItem primaryText={t('profile-search.no-results-found', 'No Results Found')} key="NO_RESULTS_FOUND" />
          )}
          {error && <ListItem primaryText={t('profile-search.error', 'Sorry an error occurred')} key="ERROR" />}
          {!isLoadingSuggestions &&
            suggestionResults.map((person) => {
              return (
                <ListItem
                  primaryText={person.primaryText}
                  secondaryText={
                    <>
                      {person.secondaryText}
                      <br />
                      {person.tertiaryText}
                    </>
                  }
                  tertiaryText={person.tertiaryText}
                  startElement={person.startElement}
                  endElement={person.endElement}
                  onClick={() => {
                    handleOnClickPerson(person)
                  }}
                  key={person.key}
                />
              )
            })}
        </List>
      </div>

      <DialogOverlayFooter>
        <Row>
          <Button onClick={handleClick} linkName="Can't Find Person">
            {t('profile-search.advancd-search.cant-find-person', "Can't Find Person?")}
          </Button>
          {optInUrl && (
            <SocialMenu
              buttonText={t('profile-search.invite-others.button', 'Invite Others')}
              sharable={{
                url: optInUrl,
                subject: t('profile-search.invite-others.header', 'Share this link with friends and family'),
                message: t('profile-search.invite-others.message', 'Connect with family and friends on FamilySearch'),
              }}
              copyLinkContent={t(
                'profile-search.invite-others.description',
                "They'll be able to connect with you easily"
              )}
              inline={false}
              linkName="Invite Others"
            />
          )}
        </Row>
      </DialogOverlayFooter>
    </>
  )
}
