import { format, isSameDay } from '@fs/zion-locale/date-fns'
import { i18n } from '@fs/zion-locale'

export default function formatChatTimestamp(timestamp) {
  const lastMessageDate = timestamp ? new Date(timestamp) : null
  const now = new Date()
  if (lastMessageDate && isSameDay(now, lastMessageDate)) {
    return format(lastMessageDate, 'p')
  }
  if (lastMessageDate && now.getFullYear() === lastMessageDate.getFullYear()) {
    const locale = i18n.language
    const options = { month: 'short', day: 'numeric' }
    return lastMessageDate.toLocaleDateString(locale, options)
  }
  if (lastMessageDate) {
    return format(lastMessageDate, 'PP', { locale: i18n.language })
  }
  return ''
}
