import { useTranslation } from 'react-i18next'
import { useHistory } from '@fs/zion-router'
import { useCallback, useEffect, useMemo, useRef } from 'react'
import { useEvent } from '@fs/zion-frontend-friends'
import { useDebouncedSuggestions } from '@fs/zion-ui'
import { useChatState, useChatDispatch } from '../providers/ChatStateProvider'
import { maxRecentContactsInProfileSearch } from '../services/userProfile/userProfileService'
import { filterSuggestionsByInputText } from './useChatInviteProfileSearch'
import {
  useFetchChatSearchSuggestions,
  useMyChatsTabChannels,
  useOpenExistingChannel,
  useOpenNewChannel,
} from './channelHooks'
import { profileSuggestionToParticipantChip } from '../chat-create/ChatCreateTo'
import { buildChatRoute, CHAT_ROUTE_KEY } from '../chat-memory-router/ChatMemoryRouter'
import getProfileSearchPeople from '../global/getProfileSearchPeople'
import { updateChannelInChannels } from '../helpers/stream/streamChatHelper'
import { findExistingChat } from '../helpers/stream/streamChatChannelsHelper'
import { CHAT_ACTIONS } from './useChatReducer'
import useChatLog from './useChatLog'

export const MAX_STREAM_SEARCH_LENGTH = 80

function useProfileSearchInclusions(suggestions, searchValue) {
  const [t] = useTranslation()
  const inclusions = useMemo(() => {
    return {
      people: [],
      suggestions: [...filterSuggestionsByInputText(suggestions, searchValue)],
      group: t('chat.recent-chats.label', 'Recent Chats'),
      maxPeople: maxRecentContactsInProfileSearch,
    }
  }, [suggestions, searchValue, t])

  return inclusions
}

function useProfileSearchExclusions() {
  const { privateChannels } = useMyChatsTabChannels()
  const twoPersonChats = privateChannels.filter((channel) => channel.data.member_count < 3)
  const exclusions = useMemo(() => getProfileSearchPeople(twoPersonChats), [twoPersonChats])
  return exclusions
}

/**
 * Navigate to an existing chat or create a new chat, placing this userId as a chip
 */
export function useHandleSelectedSearchSuggestion(onClear) {
  const [t] = useTranslation()
  const { push } = useHistory()
  const { channels, createChatRecipientChipCollection, client } = useChatState()
  const { resetChips, addChip } = createChatRecipientChipCollection
  const openExistingChannel = useOpenExistingChannel()
  const openNewChannel = useOpenNewChannel()
  const chatDispatch = useChatDispatch()
  const { log } = useChatLog({ component: '[useHandleSelectedSearchSuggestion]' })

  return useEvent(async (suggestion) => {
    const { message, channel: suggestionChannel } = suggestion || {}
    const existingChannel = await findExistingChat(channels, client, suggestionChannel?.cid, log)
    if (existingChannel) {
      chatDispatch({ type: CHAT_ACTIONS.SET_CHANNELS, channels: updateChannelInChannels(channels, existingChannel) })
      openExistingChannel(existingChannel, message?.id, message?.parent_id)
    } else if (suggestionChannel) {
      openNewChannel(suggestionChannel, message?.id, message?.parent_id)
    } else {
      resetChips()
      addChip(profileSuggestionToParticipantChip({ suggestion, t }))
      push(buildChatRoute(CHAT_ROUTE_KEY.CREATE_EMPTY_DIRECT_CHAT))
    }
    if (onClear) {
      onClear()
    }
  })
}

export default function useChatSearchChats({ disableAutoFocus }) {
  const focusRef = useRef()
  const exclusionList = useProfileSearchExclusions()
  const fetchChatSearchSuggestions = useFetchChatSearchSuggestions()
  const { inputText, setInputText, suggestions } = useDebouncedSuggestions(
    fetchChatSearchSuggestions,
    10000,
    '',
    false,
    false,
    false,
    true,
    800
  )
  const inclusions = useProfileSearchInclusions(suggestions, inputText)
  const onClear = useCallback(() => setInputText(''), [setInputText])
  const onSuggestionSelected = useHandleSelectedSearchSuggestion(onClear)

  useEffect(() => {
    let isMounted = true
    if (isMounted && !disableAutoFocus) {
      focusRef.current.focus()
    }
    return () => {
      isMounted = false
    }
  }, [focusRef, disableAutoFocus])
  return { exclusionList, inclusions, onInputTextChange: setInputText, onSuggestionSelected, onClear, focusRef }
}
