import React, { useMemo } from 'react'
import { useTranslation } from 'react-i18next'
import ChatInviteProfileSearch from '../chat-profile-search/ChatInviteProfileSearch'
import useHandleChatErrors from '../hooks/useHandleChatErrors'

export function profileSuggestionToParticipantChip({ suggestion, t }) {
  return {
    label: suggestion.displayName || suggestion.primaryText,
    value: suggestion.displayName || suggestion.primaryText,
    'aria-label': suggestion.displayName || suggestion.primaryText,
    dismissAriaLabel: t('common-ui:remove.action', 'Remove'),
    suggestion,
  }
}

export function channelMemberToParticipantChip({ member, t }) {
  const name = member?.user?.name
  return {
    label: name,
    value: name,
    'aria-label': name,
    dismissAriaLabel: t('common-ui:remove.action', 'Remove'),
    suggestion: {
      key: member?.user?.fs_cis_id, // this is how ChatCreateTo knows to exclude this user from its autosuggest
    },
  }
}

export default function ChatCreateTo({ disabled, recipientChipCollection }) {
  const { noCisIdError } = useHandleChatErrors()
  const [t] = useTranslation()
  const { addChip, chips } = recipientChipCollection
  const excludedUsers = useMemo(() => {
    return [
      ...(chips || []).map((chip) => {
        return { cisId: chip?.suggestion?.key }
      }),
    ]
  }, [chips])

  return (
    <ChatInviteProfileSearch
      disabled={disabled}
      excludedUsers={excludedUsers}
      onClickSuggestion={(suggestion) => {
        if (!suggestion.key.startsWith('cis.user')) {
          noCisIdError()
          return
        }
        if (!excludedUsers.find((user) => user.cisId === suggestion.key)) {
          const chip = profileSuggestionToParticipantChip({ suggestion, t })
          addChip(chip)
        }
      }}
    />
  )
}
