import React from 'react'
import { useTranslation } from 'react-i18next'
import { Paragraph, DialogOverlayActions, Button } from '@fs/zion-ui'
import { SocialMenu } from '@fs/zion-social'
import { buildLangUrl } from '@fs/zion-router'

export function ProfileSearchInviteDialogContent() {
  const [t] = useTranslation()
  return (
    <>
      <Paragraph>
        {t(
          'profile-search.invite-dialog-content-1',
          'This person is a member of your ward or stake but does not yet have a FamilySearch account. '
        )}
      </Paragraph>
      <Paragraph>
        {t(
          'profile-search.invite-dialog-content-2',
          'An account is needed to send and receive messages on FamilySearch. '
        )}
      </Paragraph>
      <Paragraph>
        {t('profile-search.invite-dialog-content-3', 'Would you like to invite this person to sign up?')}
      </Paragraph>
    </>
  )
}

export function ProfileSearchInviteDialogFooter({ overlay }) {
  const [t] = useTranslation()
  const cancelText = t('common-ui:cancel.action', 'Cancel')
  const actionText = t('profile-search.invite-dialog-footer-invite', 'Invite')
  return (
    <DialogOverlayActions>
      <Button onClick={overlay.close} title={cancelText} data-testid="profile-search-close-invite-overlay">
        {cancelText}
      </Button>
      <SocialMenu
        buttonText={actionText}
        sharable={{
          url: buildLangUrl('https://www.familysearch.org/identity/signup/'),
        }}
        buttonEmphasis="high"
        platforms={['facebook', 'messenger', 'twitter', 'whatsApp', 'email', 'copyLink']}
        copyLinkContent={t(
          'profile-search.invite-dialog-footer-copy-link',
          'Share this link to invite someone to create a FamilySearch account.'
        )}
      />
    </DialogOverlayActions>
  )
}
