import React, { forwardRef, useEffect, useState } from 'react'
import { Alert, Autosuggest, DialogOverlay, BillboardButton, useOverlay } from '@fs/zion-ui'
import { Trans } from 'react-i18next/icu.macro'
import { NoticeLoading, MenuSearch } from '@fs/zion-icon'
import zionDebug from '@fs/zion-debug'
import { ContactOverlay } from '@fs/zion-contact-overlay'
import PropTypes from 'prop-types'
import { useTranslation } from 'react-i18next'
import { useUserProfile } from '@fs/zion-user'
import ProfileSearchProvider, { useProfileContext } from './ProfileSearchProvider'
import { getPortraitUrl, warmUpConnectionsApi } from './profileSearchServices'
import { MAX_SEARCH_LENGTH, useProfileSuggestions, warningValidate } from './profileSearchHooks'
import AdvancedSearchOverlayContent from './AdvancedSearchOverlayContent'
import OptInDialog from './OptInDialog/ProfileOptInDialog'
import { ProfileSearchInviteDialogContent, ProfileSearchInviteDialogFooter } from './profileSearchInviteDialogContent'

const debug = zionDebug('zion:profile-search')

const ProfileSearch = forwardRef(function ProfileSearch(
  {
    onSuggestionSelected = () => {},
    exclusionList = null,
    inclusions = null,
    removeAdvancedSearch = false,
    onInputTextChange,
    selectedItem,
    disabled = false,
    label,
    clearInputOnSelection = false,
    onClear = () => {},
    onBlur = () => {},
    placeholder = '',
    hideMessaging = false,
    optInUrl,
    promptOptIn = true,
    shouldUseUserConnections = false,
    ...extraProps
  },
  ref
) {
  // maybe cache this later so it is only called the first time the component loads.
  useEffect(() => {
    if (shouldUseUserConnections) {
      warmUpConnectionsApi()
    }
  }, [shouldUseUserConnections])

  return (
    <ProfileSearchProvider
      onSuggestionSelected={onSuggestionSelected}
      exclusionList={exclusionList}
      inclusions={inclusions}
      removeAdvancedSearch={removeAdvancedSearch}
      onInputTextChange={onInputTextChange}
      selectedItem={selectedItem}
      disabled={disabled}
      label={label}
      clearInputOnSelection={clearInputOnSelection}
      onClear={onClear}
      onBlur={onBlur}
      placeholder={placeholder}
      hideMessaging={hideMessaging}
      optInUrl={optInUrl}
      promptOptIn={promptOptIn}
      shouldUseUserConnections={shouldUseUserConnections}
    >
      <ProfileSearchCore {...extraProps} ref={ref} />
    </ProfileSearchProvider>
  )
})

const ProfileSearchCore = forwardRef(function ProfileSearchCore({ ...extraProps }, ref) {
  const {
    contactSelected,
    removeAdvancedSearch,
    clearInputOnSelection,
    onSuggestionSelected: onUserSuggestionSelected,
    onInputTextChange,
    selectedItem,
    disabled,
    label,
    onBlur,
    onClear,
    placeholder,
    hideMessaging,
    promptOptIn,
  } = useProfileContext()
  const [t] = useTranslation()
  const [dialogDismissed, setDialogDismissed] = useState(false)
  const { userProfile, userProfileLoading } = useUserProfile()
  const searchableStatus = userProfile?.searchable?.status
  const [nameValue, setNameValue] = useState('')
  // We need to use countryOptions to fill in the country values for each person
  const advancedSearchOption = removeAdvancedSearch
    ? null
    : { key: 'LAST_RESORT', primaryText: t('profile-search.header.advanced-search', 'Advanced Search') }

  const advancedSearchOverlay = useOverlay()
  const contactOverlay = useOverlay()
  const optInOverlay = useOverlay()
  const inviteOverlay = useOverlay()

  const { handleClick: openInviteOverlay } = inviteOverlay
  // for the icon buttons of each suggested person
  const { handleClick: openContactOverlay } = contactOverlay

  const { suggestionResults, isLoadingSuggestions } = useProfileSuggestions(
    openContactOverlay,
    false,
    nameValue,
    openInviteOverlay
  )

  function onSuggestionSelected(suggestion) {
    debug('on suggestion selected person:', suggestion)
    if (suggestion && suggestion?.type === 'LAST_RESORT') {
      if (!advancedSearchOverlay.isOpen) {
        advancedSearchOverlay.handleClick()
      }
    }
    if (suggestion && suggestion?.type !== 'LAST_RESORT') {
      // clear input to be able to select another person
      if (clearInputOnSelection) {
        setNameValue('')
      }
      onUserSuggestionSelected?.(suggestion)
    }
  }

  function handleInputTextChange(text) {
    setNameValue(text)
    onInputTextChange?.(text)
  }

  return (
    <div>
      <Autosuggest
        name="search"
        warningValidate={(text) => warningValidate(text)}
        suggestions={suggestionResults}
        onSuggestionSelected={onSuggestionSelected}
        inputText={nameValue}
        onInputTextChange={(text) => handleInputTextChange(text)}
        selectedItem={selectedItem}
        Icon={isLoadingSuggestions ? NoticeLoading : MenuSearch}
        noFilter
        highlightMatchingText
        ignoreDiacritics={false}
        lastResort={advancedSearchOption}
        disabled={disabled}
        label={label}
        clearable
        onClear={onClear}
        onBlur={onBlur}
        placeholder={placeholder}
        inputProps={{}}
        itemProps={{}}
        menuProps={{}}
        maxLength={MAX_SEARCH_LENGTH}
        clearOnClickAway
        showLastResortOnFocus // always be able to access advanced search
        keepUserInputTextAlways
        ref={ref}
        aria-label={placeholder}
        data-testid={extraProps?.['data-testid'] || 'profile-regular-search'} // Let consuming apps override if needed.
        {...extraProps}
      />
      {promptOptIn && userProfile && searchableStatus !== 'LISTED' && !dialogDismissed && (
        <Alert type="warning" dismissable onDismiss={() => {}}>
          <Trans
            i18nKey="profile-search.opt-in-suggestion"
            defaults="Currently your family and friends may not be able to contact you on FamilySearch. <OptInButton> Click to fix this. </OptInButton>"
            components={{
              OptInButton: <BillboardButton color="blue" emphasis="low" onClick={optInOverlay.handleClick} />,
            }}
          />
        </Alert>
      )}
      {/* TODO: The 'autoWidth' prop on DialogOverlay has been removed in zion-ui v11. Please remove it here and use the new 'size' prop in its place. */}
      <DialogOverlay
        title={t('profile-search.header.advanced-search', 'Advanced Search')}
        {...advancedSearchOverlay}
        // autoWidth
      >
        <AdvancedSearchOverlayContent
          initialInputValue={nameValue}
          overlay={{ ...advancedSearchOverlay }}
          onSuggestionSelected={onSuggestionSelected}
          openContactOverlay={openContactOverlay}
        />
      </DialogOverlay>
      <ContactOverlay
        contact={contactSelected || { cisId: '' }}
        portraitUrl={contactSelected?.cisId ? getPortraitUrl(contactSelected?.cisId) : ''}
        hideMessaging={hideMessaging}
        overlay={contactOverlay}
        handleClick={openContactOverlay}
      />
      <DialogOverlay
        footer={<ProfileSearchInviteDialogFooter overlay={inviteOverlay} />}
        title={t('profile-search.header.no-cis-id', 'No FamilySearch Account')}
        {...inviteOverlay}
      >
        <ProfileSearchInviteDialogContent />
      </DialogOverlay>

      {searchableStatus !== 'LISTED' && !userProfileLoading && (
        <OptInDialog
          overlay={optInOverlay}
          onOptIn={() => {
            setDialogDismissed(true)
          }}
          onOptOut={() => {
            setDialogDismissed(true)
          }}
        />
      )}
    </div>
  )
})

ProfileSearch.propTypes = {
  /** Do something with the suggestion selected, where suggestion is an AutoSuggest Suggestion */
  onSuggestionSelected: PropTypes.func,

  /** An array of peopleObjects with a contactId or cisId to be exclusionListed from the search results */
  exclusionList: PropTypes.arrayOf(
    PropTypes.shape({
      cisId: PropTypes.string,
      contactId: PropTypes.string,
    })
  ),

  /** A object that allows the developer to add suggestions to the beginning of the list of people shown in the dropdown. The default maxPeople is 5. */
  inclusions: PropTypes.shape({
    people: PropTypes.arrayOf(PropTypes.shape({ cisId: PropTypes.string.isRequired, isOnline: PropTypes.bool })),
    suggestions: Autosuggest.propTypes.suggestions,
    group: PropTypes.string,
    maxPeople: PropTypes.number,
  }),

  /** Called each time the input text changes. */
  onInputTextChange: PropTypes.func,

  /** Autosuggest prop: Set the selected item. Set the entire object as opposed to just the input text. This is the Downshift selectedItem property.  */
  selectedItem: Autosuggest.propTypes.selectedItem,

  /** Disable input */
  clearInputOnSelection: PropTypes.bool,

  /** Disable input */
  disabled: PropTypes.bool,

  /** The text for the label for the input. */
  label: PropTypes.string,

  /** Allows the field to be cleared. Adds a "clear" button. */
  clearable: PropTypes.bool,

  /** Handler run when the field is cleared. Will set clearable to true if provided and clearable is not provided. */
  onClear: PropTypes.func,

  /** Runs when the user blurs away from TextField (see TextField docs for more). */
  onBlur: PropTypes.func,

  /** A placeholder for the underlying TextField (see TextField docs for more). */
  placeholder: PropTypes.string,

  /** Autosuggest prop: Clear the text field when blurred */
  clearOnClickAway: PropTypes.bool,

  /** Autosuggest prop: Set to true if you want the user's text to always remain in the input, even when an item is selected. */
  keepUserInputTextAlways: PropTypes.bool,

  /** Not recommended to hide the advanced search option, unless absolutely necessary */
  removeAdvancedSearch: PropTypes.bool,

  /** Use the new connections url and design */
  shouldUseUserConnections: PropTypes.bool,
}

export default ProfileSearch
