import { useEffect, useMemo, useRef, useState } from 'react'
import { i18n } from '@fs/zion-locale'
import { useMyChatsTabChannels } from './channelHooks'
import getProfileSearchPeople from '../global/getProfileSearchPeople'
import { filterChannels } from '../helpers/stream/streamChatHelper'
import {
  debouncedGetUserProfileSuggestions,
  maxRecentContactsInProfileSearch,
} from '../services/userProfile/userProfileService'

export function removeDiacritics(str) {
  // normalize() converts a string into unicode, from which we can replace a range of diacritic characters
  // https://stackoverflow.com/questions/990904/remove-accents-diacritics-in-a-string-in-javascript
  // https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Global_Objects/String/normalize
  return str.normalize('NFD').replace(/[\u0300-\u036f]/g, '')
}

function includesInputText(suggestionText, inputText) {
  if (!inputText) {
    return true
  }
  if (suggestionText) {
    const normalizedSuggestionText = removeDiacritics(suggestionText).toLowerCase()
    const normalizedInputText = removeDiacritics(inputText).toLowerCase().trim()
    return normalizedSuggestionText.includes(normalizedInputText)
  }
  return false
}

export function filterInclusionsByInputText(inclusions, inputText) {
  return inclusions.suggestions.filter((s) => {
    if (inputText && inputText[0] === '@') {
      return includesInputText(s.contactId, inputText.substring(1))
    }
    return (
      includesInputText(s.primaryText, inputText) ||
      includesInputText(s.secondaryText, inputText) ||
      includesInputText(s.tertiaryText, inputText)
    )
  })
}

export function filterSuggestionsByInputText(suggestions, inputText) {
  return suggestions.filter((s) => {
    return (
      includesInputText(s.primaryText, inputText) ||
      includesInputText(s.secondaryText, inputText) ||
      includesInputText(s.tertiaryText, inputText) ||
      includesInputText(s.message?.text, inputText)
    )
  })
}

export default function useChatInviteProfileSearch(excludedUsers, openAutosuggestByDefault) {
  const focusRef = useRef()
  const [inputText, setInputText] = useState('')
  const { privateChannels } = useMyChatsTabChannels()
  const [profilePeopleSuggestions, setProfilePeopleSuggestions] = useState([])
  const exclusionList = useMemo(
    () => [...getProfileSearchPeople(privateChannels, excludedUsers), ...excludedUsers],
    [privateChannels, excludedUsers]
  )
  const privateChatsMatchingSearchValue = useMemo(
    () => filterChannels(privateChannels, inputText),
    [privateChannels, inputText]
  )
  const profilePeople = useMemo(
    () => getProfileSearchPeople(privateChatsMatchingSearchValue, excludedUsers),
    [privateChatsMatchingSearchValue, excludedUsers]
  )
  const inclusions = useMemo(() => {
    const suggestions = [...profilePeopleSuggestions]
    return {
      people: [],
      suggestions,
      group: i18n.t('chat.recent-chats.label', 'Recent Chats'),
      maxPeople: maxRecentContactsInProfileSearch,
    }
  }, [profilePeopleSuggestions])

  useEffect(() => {
    let isMounted = true
    if (profilePeople?.length > 0) {
      debouncedGetUserProfileSuggestions({ profilePeople }).then((profileSuggestions) => {
        if (isMounted) {
          setProfilePeopleSuggestions(profileSuggestions)
        }
      })
    }
    return () => {
      isMounted = false
    }
  }, [profilePeople])

  useEffect(() => {
    // automatically focus and open the 'Invite People/TO' Autosuggest
    focusRef?.current?.focus()
    if (openAutosuggestByDefault) {
      focusRef?.current?.click()
    }
  }, [openAutosuggestByDefault])

  const filteredInclusions = useMemo(() => {
    const suggestions = filterInclusionsByInputText(inclusions, inputText)
    return { ...inclusions, suggestions }
  }, [inputText, inclusions])
  return { setInputText, exclusionList, focusRef, inclusions: filteredInclusions }
}
