function addAnalyticsParam(url, product, appName) {
  if (!url) return ''
  let urlObj = ''
  try {
    urlObj = new URL(url)
  } catch {
    return urlObj
  }
  urlObj.searchParams.append('cid', `${product}_${appName.toLowerCase()}`)

  return urlObj.toString()
}

const centerWindowPosition = (width, height) => {
  // TODO: SSR needs to be addressed here
  const screenLeft = window.screenLeft ? window.screenLeft : window.screenX
  const screenTop = window.screenTop ? window.screenTop : window.screenY
  return {
    left: screenLeft + window.innerWidth / 2 - width / 2,
    top: screenTop + window.innerHeight / 2 - height / 2,
  }
}

let previouslySharedUrl
const buildWindowSpecs = (config) => {
  // TODO: SSR - No oping for now. this code doesn't make sense for SSR right now. Figure this out
  if (!hasWindow) return ''

  const { width, height } = config.window
  const { left, top } = centerWindowPosition(width, height)
  const windowFeatures = {
    left,
    top,
    width,
    height,
    scrollbars: 'yes', // a11y recommends this be on
    resizable: 'yes', // a11y recommends this be on
    toolbar: 'no',
    location: 'no',
    status: 'no',
    menubar: 'no',
    titlebar: 'no',
  }
  const specs = Object.keys(windowFeatures)
    .map((feature) => `${feature}=${windowFeatures[feature]}`)
    .join(',')
  return specs
}

const openWindow = (config, specs) => {
  const { name, formattedUrl } = config
  if (!formattedUrl) return
  // NOTE: This stuff is following the best practices from Mozilla for window.open
  if (config.window.ref == null || config.window.ref.closed) {
    config.window.ref = window.open(formattedUrl, name, specs)
  } else if (previouslySharedUrl !== formattedUrl) {
    config.window.ref = window.open(formattedUrl, name, specs)
    config.window.ref.focus()
  } else {
    config.window.ref.focus()
  }
  previouslySharedUrl = config.formattedUrl
}

// Keeping this logic inside SocialShare to avoid having a direct dependency on zion-chat
const buildChatUrl = (sharable) => {
  const { url, urlDisplayText, subject } = sharable
  const chatUrl = new URL(window.location.href)
  chatUrl.searchParams.set('chatRoute', '/chat-create/fs_direct')
  if (url) {
    chatUrl.searchParams.set('aboutLink', url)
  }
  if (urlDisplayText) {
    chatUrl.searchParams.set('aboutText', urlDisplayText)
  }
  if (subject) {
    chatUrl.searchParams.set('messageText', subject)
  }
  return chatUrl.toString()
}

