const buildUrl = async (appConfig) => {
  const { url, urlToShare, name, product } = appConfig
  if (name === 'FamilySearch Chat') {
    return url
  }
  let newUrl = urlToShare
  if (typeof urlToShare === 'function') {
    const returnedUrl = await urlToShare()
    newUrl = typeof returnedUrl === 'string' ? returnedUrl : ''
  }
  const shareableUrl = addAnalyticsParam(newUrl, product, name)

  if (name === 'Copy') {
    return shareableUrl // The Copy url should not be encoded.
  }

  return url + encodeURIComponent(shareableUrl)
}

/**
 * Safari is blocking any call to window.open() which is made inside an async
 * call. So as a work around, we open the window, then make the function call
 * to get the url (however long that takes) and then redirect the window.
 * For Reference:
 * https://stackoverflow.com/questions/20696041/window-openurl-blank-not-working-on-imac-safari
 * @param {Object} appConfig config for the app
 * @param {Object} specs the window specs
 */
const socialButtonClickForSafari = async (appConfig, specs) => {
  if (!isIosDevice()) appConfig.window.ref = window.open('', appConfig.name, specs)

  appConfig.formattedUrl = await buildUrl(appConfig)
  handleAnalytics(appConfig)

  if (isIosDevice()) {
    window.location = appConfig.formattedUrl
  } else {
    appConfig.window.ref.location = appConfig.formattedUrl
  }
}

const socialButtonClick = async ({ appConfig, ...socialOverlay }) => {
  const specs = buildWindowSpecs(appConfig)
  if ((isUsingBrowser('Safari') && !isUsingBrowser('Chrome')) || isUsingBrowser('Firefox')) {
    socialButtonClickForSafari(appConfig, specs)
  } else {
    appConfig.formattedUrl = await buildUrl(appConfig)
    handleAnalytics(appConfig)
    openWindow(appConfig, specs)
  }
  if (socialOverlay && Object.keys(socialOverlay).length > 0) socialOverlay.close()
}

// Email needs the URL synchronously to set the `to` prop for its Link
const getEmailLinkUrl = (appConfig) => {
  const { url, urlToShare, name, product } = appConfig
  const shareableUrl = addAnalyticsParam(urlToShare, product, name)
  return url + encodeURIComponent(shareableUrl)
}

const kakaoTalkShare = ({ title, description, imageUrl, urlToShare }) => {
  window.Kakao.Link.sendDefault({
    objectType: 'feed',
    content: {
      title,
      description,
      imageUrl,
      link: {
        mobileWebUrl: urlToShare,
        webUrl: urlToShare,
      },
    },
  })
}

// KakaoTalk requires an SDK. As an optimization, the SDK will only be loaded when the KakaoTalk share button has been selected
const kakaoTalkClicked = (config, { setLoadingButton, index: buttonIndex }) => {
  if (!hasWindow) return

  const kakaoSDK = document.getElementById('kakaoSDK')

  if (!kakaoSDK) {
    setLoadingButton({ loading: true, index: buttonIndex })
    const script = document.createElement('script')
    script.id = 'kakaoSDK'
    script.src = 'https://developers.kakao.com/sdk/js/kakao.min.js'
    script.onload = function onKakaoSDKLoad() {
      window.Kakao.init(kakaoSDKId)
      kakaoTalkShare(config)
      setLoadingButton({ loading: false, index: null })
    }
    document.body.appendChild(script)
  } else {
    kakaoTalkShare(config)
  }
}

