const CopyDialog = ({ copyOverlay, subject, copyLinkContent, onCopyClick, t, config }) => {
  const [copyUrl, setCopyUrl] = useState()
  const { isOpen, transitioning } = copyOverlay
  const targetRef = useRef()

  useEffect(() => {
    let isCurrent = true
    if (isOpen && transitioning) {
      ;(async () => {
        try {
          const formattedUrl = await buildUrl(config)
          if (isCurrent) setCopyUrl(formattedUrl)
        } catch (err) {
          console.error(err)
        }
      })()
    }
    return () => {
      isCurrent = false
    }
  }, [config, isOpen, transitioning])

  return copyUrl ? (
    <DialogOverlay {...copyOverlay} title={subject} focusRef={targetRef}>
      {copyLinkContent && (
        <>
          <Paragraph centered>{copyLinkContent}</Paragraph>
          <Separator size="xs" />
        </>
      )}
      <Suspense fallback={<Skeleton.Image width={300} height={300} />}>
        <Row alignX="center">
          <QRCodeSVG
            value={copyUrl}
            role="img"
            aria-label={t('social.share.qrCodeLabel', 'QR code of the link to this page')}
            className={qrCodeCss}
          />
        </Row>
      </Suspense>
      <DialogOverlayFooter>
        <DialogOverlayActions>
          <TextField type="url" value={copyUrl} placeholder="http://..." growX />
          <Button ref={targetRef} onClick={() => onCopyClick(copyUrl)} emphasis="medium">
            {t('common-ui:copy.action', 'Copy')}
          </Button>
        </DialogOverlayActions>
      </DialogOverlayFooter>
    </DialogOverlay>
  ) : null
}

const SocialListItems = ({ platforms, copyOverlay, onEmailClick, onDownloadClick, config, ...props }) => {
  const [loadingButton, setLoadingButton] = useState({ index: null, loading: false })
  const { t } = useTranslation()
  const [canAddPersonalData, canAddPersonalDataStatus] = useCanAddPersonalData()
  const [hasLegalAgePermission, legalAgePermissionStatus] = usePermission('FsChatLegalAgePermission', 'FsChat')
  const supportedOptions = getSupportedOptions({
    config,
    t,
    copyOverlay,
    onEmailClick,
    onDownloadClick,
    ...props,
  })
  const availableOptions = Object.keys(supportedOptions).reduce((accumulator, currentValue, index) => {
    const option = { ...supportedOptions[currentValue] }
    const buttonIcon = loadingButton.loading && loadingButton.index === index ? NoticeLoading : option.Icon
    option.startElement = <ListItem.Icon Icon={buttonIcon} />
    option.primaryText = <Ellipsis>{option.label}</Ellipsis>
    option.key = option.label
    const onClickWithConfig = option.onClick.bind(option)
    option.onClick = () => onClickWithConfig({ setLoadingButton, index })
    delete option.Icon
    delete option.label
    accumulator[currentValue] = option
    return accumulator
  }, {})
  let items = platforms.map((option) => availableOptions[option])

  // Filter out Social Media Entries that are blocked by CanAddData and LegalAge Permissions if not allowed to access
  // Filter out permission props so they don't get passed to DOM element
  if (canAddPersonalDataStatus !== 'loading' && !canAddPersonalData) {
    items = items.filter((item) => !item.needsAddPersonalDataPermission)
  }

  if (legalAgePermissionStatus !== 'loading' && !hasLegalAgePermission) {
    items = items.filter((item) => !item.needsLegalAgePermission)
  }

  items = items.map((item) => {
    const { needsAddPersonalDataPermission, needsLegalAgePermission, ...rest } = item
    return rest
  })

  return items.map((item) => item && <ListItem {...item} />)
}

export function SocialMenu({
  useIconButton = false,
  buttonEmphasis = 'medium',
  billboardButtonColor,
  platforms = defaultPlatforms,
  sharable,
  copyLinkContent,
  product = 'fs',
  analytics = {},
  inline = true,
  buttonText,
  hideIcon = false,
  Icon,
  onEmailClick,
  onDownloadClick,
  downloadUrl,

  ...props
}) {
  const { t } = useTranslation()
  const menuButtonRef = useRef()
  const menuOverlay = useMenuOverlay()
  const copyOverlay = useOverlay({ focusBackRef: menuButtonRef })
  const showStatusOverlay = useStatusOverlay()

  // If url is a function, store its return value when the menu is first opened
  const { url: urlStringOrFunc } = sharable
  const isUrlFunction = typeof urlStringOrFunc === 'function'
  const [url, setUrl] = useState(isUrlFunction ? null : urlStringOrFunc)
  const [loadingUrl, setLoadingUrl] = useState(false)

  useEffect(() => {
    if (!isUrlFunction) setUrl(sharable.url)
  }, [isUrlFunction, sharable.url])

  product = product === '' ? 'fs' : product
  platforms = platforms.length === 0 ? defaultPlatforms : platforms
  sharable.subject = sharable.subject || ''

  // Don’t generate config until we have the URL
  const config = url ? configs({ ...sharable, url }, product, analytics, downloadUrl) : null
  const shareText = buttonText || t('social.share.action', 'Share')
  const ButtonIcon = loadingUrl ? NoticeLoading : Icon || SocialShare

  const handleMenuButtonClick = async (event) => {
    const { currentTarget: button } = event
    if (url) {
      menuOverlay.open({ target: button })
    } else {
      setLoadingUrl(true)
      try {
        const returnedUrl = await urlStringOrFunc()
        if (returnedUrl && typeof returnedUrl === 'string') {
          setUrl(returnedUrl)
          menuOverlay.open({ target: button })
        }
      } catch (error) {
        // Consumer is responsible for handling errors (e.g., with a StatusOverlay)
      } finally {
        setLoadingUrl(false)
      }
    }
  }

  const ButtonComponent = billboardButtonColor ? BillboardButton : Button
  const menuButton = useIconButton ? (
    <IconButton
      {...sanitizeProps(props)}
      {...menuOverlay.menuButtonProps}
      ref={menuButtonRef}
      Icon={ButtonIcon}
      aria-label={shareText}
      onClick={handleMenuButtonClick}
      disabled={loadingUrl}
    />
  ) : (
    <ButtonComponent
      {...sanitizeProps(props)}
      {...menuOverlay.menuButtonProps}
      ref={menuButtonRef}
      Icon={hideIcon ? null : ButtonIcon}
      emphasis={buttonEmphasis}
      color={billboardButtonColor}
      onClick={handleMenuButtonClick}
      disabled={loadingUrl}
    >
      {shareText}
    </ButtonComponent>
  )

  const handleCopy = useCallback(
    (text) => {
      copyToClipboard(text)
      showStatusOverlay({
        message: t('social.copy-confirmation', 'Link copied to clipboard'),
        transient: true,
      })
      copyOverlay.close()
    },
    [copyOverlay, showStatusOverlay, t]
  )

  return (
    <>
      {menuButton}
      <MenuOverlay {...menuOverlay} inline={inline} aria-label={t('social.share-menu', 'Share Menu')}>
        {url && (
          <SocialListItems
            config={config}
            platforms={platforms}
            copyOverlay={copyOverlay}
            onEmailClick={onEmailClick}
            onDownloadClick={onDownloadClick}
          />
        )}
      </MenuOverlay>
      {url && (
        <CopyDialog
          copyOverlay={copyOverlay}
          subject={sharable.subject}
          copyLinkContent={copyLinkContent}
          onCopyClick={(copyUrl) => handleCopy(copyUrl)}
          t={t}
          config={config.copyLink}
        />
      )}
    </>
  )
}

const commonPropTypes = {
  /** The product that needs to log cid analytic information about what features are being used. e.g. 'mem' for memories */
  product: PropTypes.string,

  /** The analytics metrics to send to Adobe Analytics for clicks on buttons to open a share dialog overlay. Analytics metrics are only sent if this property is specified.  */
  analytics: PropTypes.shape({
    /** The name of the link or button that was clicked to launch the menu */
    link_name: PropTypes.string,

    /** The name of the page where the SocialDialog is displayed. */
    link_page: PropTypes.string,

    /** The name of the web app that served the page. If not specified, the product prop value will be used. */
    link_app: PropTypes.string,
  }),

  /** The payload to share with the chosen option. `url` being a function is supported _only_ by SocialMenu (and not by SocialBar or SocialDialog).  */
  sharable: PropTypes.shape({
    /** Should be a fully qualified https://www.familysearch.org... url in order to work and support analytics. */
    url: PropTypes.oneOfType([PropTypes.string, PropTypes.func]).isRequired,

    /** The text to display in place of the full url. Only supported for FamilySearch Chat. If not provided, the whole url will be displayed. */
    urlDisplayText: PropTypes.string,

    /** The payload to share with the chosen option. Not all social platforms support a subject. */
    subject: PropTypes.string,

    /** The message to share. Not all social platforms support a message. */
    message: PropTypes.string,

    /** The image url to share. Currently only supported/necessary for Kakao Talk */
    imageUrl: PropTypes.string,
  }).isRequired,

  /** Displays in the copy dialog content area */
  copyLinkContent: PropTypes.string,

  /** Shows the chosen share options. */
  platforms: PropTypes.arrayOf(PropTypes.oneOf([...defaultPlatforms, 'kakaoStory', 'kakaoTalk', 'download'])),

  /** Fired when email is an option specified in `platforms` and clicked. When not specified, the default email client opens. */
  onEmailClick: PropTypes.func,

  /** Fired when download is an option specified in `platforms` and clicked. When not specified, the `sharable`'s `downloadUrl` is used. */
  onDownloadClick: PropTypes.func,

  /** Download URL. Should still be fully qualified. Represents an image or document, not a webpage. For more dynamic content, use the onDownloadClick callback. */
  downloadUrl: PropTypes.string,
}

SocialMenu.propTypes = {
  ...commonPropTypes,

  /** The emphasis to give the Share button. `lightHigh` is only valid when `billboardButtonColor` is provided. */
  buttonEmphasis: PropTypes.oneOf(['low', 'medium', 'high', 'lightHigh']),

  /** Text to be displayed in the button. Defaults to "Share" */
  buttonText: PropTypes.string,

  /** A billboard color for the button. NOTE: Including this prop will switch the underlying Button to BillboardButton. */
  billboardButtonColor: PropTypes.oneOf(['blue', 'green', 'yellow', 'red', 'purple', 'gray']),

  /** An Icon to display in the SocialMenu button. Defaults to SocialShare. */
  Icon: PropTypes.elementType,

  /** Optionally have the menu be next to the button in the DOM for better accessibility.  If set to false, this overlay will be rendered in a portal instead. Use this prop if your overlay is being cut off because one of its ancestors has `overflow: hidden` */
  inline: PropTypes.bool,

  /** When set, the Share button becomes an IconButton */
  useIconButton: PropTypes.bool,

  /** Hide the share icon for the button with text. Defaults to false */
  hideIcon: PropTypes.bool,
}

function SocialButton({ label, useIconButtons, ...props }) {
  const title = props['aria-label'] || label
  if (useIconButtons) {
    return <IconButton aria-label={title} title={title} {...props} />
  }
  return <Button {...{ ...props, title }}>{label}</Button>
}

export function SocialBar({
  useIconButtons = false,
  platforms = defaultPlatforms,
  sharable,
  copyLinkContent,
  product = 'fs',
  analytics = {},
  onEmailClick,
  onDownloadClick,
  downloadUrl,
  color = 'blue',
  /** INTERNAL */
  onCopyClick,
  ...props
}) {
  const [loadingButton, setLoadingButton] = useState({ index: null, loading: false })
  const { t } = useTranslation()
  const copyOverlay = useOverlay()
  const showStatusOverlay = useStatusOverlay()
  const [canAddPersonalData, canAddPersonalDataStatus] = useCanAddPersonalData()
  const [hasLegalAgePermission, legalAgePermissionStatus] = usePermission('FsChatLegalAgePermission', 'FsChat')

  product = product === '' ? 'fs' : product
  platforms = platforms.length === 0 ? defaultPlatforms : platforms
  sharable.subject = sharable.subject || ''
  const { subject } = sharable
  const config = configs(sharable, product, analytics, downloadUrl)
  const supportedOptions = getSupportedOptions({
    config,
    t,
    copyOverlay,
    onEmailClick,
    onDownloadClick,
  })
  let buttons = platforms.map((platform) => ({ ...supportedOptions[platform], platform }))

  // Filter out Social Media Entries that are blocked by CanAddData Permissions if not allowed to access
  // Filter out needsAddPersonalDataPermission prop so it doesn't get passed to DOM element
  if (canAddPersonalDataStatus !== 'loading' && !canAddPersonalData) {
    buttons = buttons.filter((button) => !button.needsAddPersonalDataPermission)
  }

  if (legalAgePermissionStatus !== 'loading' && !hasLegalAgePermission) {
    buttons = buttons.filter((button) => !button.needsLegalAgePermission)
  }

  buttons = buttons.map((item) => {
    const { needsAddPersonalDataPermission, needsLegalAgePermission, ...rest } = item
    return rest
  })

  const handleCopy = useCallback(
    (text) => {
      copyToClipboard(text)
      showStatusOverlay({
        message: t('social.copy-confirmation', 'Link copied to clipboard'),
        transient: true,
      })
      copyOverlay.close()
      onCopyClick()
    },
    [copyOverlay, showStatusOverlay, t, onCopyClick]
  )
  const buttonIcon = (index, Icon) => (loadingButton.loading && loadingButton.index === index ? NoticeLoading : Icon)

  return (
    <>
      <Row wrap {...props}>
        {buttons.map(({ label, Icon, onClick, platform, ...buttonProps }, index) => {
          // For the copy button, we need to pass the event to useOverlay's handleClick
          // to ensure focus is returned to the button when the dialog closes.
          const finalOnClick =
            platform === 'copyLink'
              ? (event) => {
                  handleAnalytics(config.copyLink)
                  copyOverlay.handleClick(event)
                }
              : () => onClick({ setLoadingButton, index })

          return (
            <SocialButton
              key={label}
              Icon={buttonIcon(index, Icon)}
              onClick={finalOnClick}
              label={label}
              useIconButtons={useIconButtons}
              color={color}
              {...buttonProps}
            />
          )
        })}
      </Row>

      <CopyDialog
        copyOverlay={copyOverlay}
        subject={subject}
        copyLinkContent={copyLinkContent}
        onCopyClick={(copyUrl) => handleCopy(copyUrl)}
        t={t}
        config={config.copyLink}
      />
    </>
  )
}

SocialBar.propTypes = {
  ...commonPropTypes,

  /** When set, the bar of Buttons become IconButtons */
  useIconButtons: PropTypes.bool,

  /** Button color */
  color: PropTypes.oneOf(['blue', 'gray']),
}

export function SocialDialog({
  platforms = defaultPlatforms,
  sharable,
  copyLinkContent,
  product = 'fs',
  analytics = {},
  onEmailClick,
  onDownloadClick,
  close,
  ...props
}) {
  const { t } = useTranslation()

  const onCopyClick = useCallback(() => {
    close()
  }, [close])
  const content = (
    <LayoutBand>
      <SocialBar
        sharable={sharable}
        product={product}
        analytics={analytics}
        platforms={platforms}
        onDownloadClick={onDownloadClick}
        onEmailClick={onEmailClick}
        onCopyClick={onCopyClick}
        alignX="center"
        {...props}
      />
    </LayoutBand>
  )
  return (
    <DialogOverlay {...props} close={close} title={t('social.share.action', 'Share')}>
      {content}
    </DialogOverlay>
  )
}

SocialDialog.propTypes = {
  ...commonPropTypes,

  /** REQUIRED: Social Dialog needs all the props provided from the useOverlay hook in order to work. */
  '{...useOverlay()}': PropTypes.object,
}
