import React from 'react'
import { ListItem, Avatar } from '@fs/zion-ui'
import { MultiAvatar } from '@fs/zion-ui/quarks-authorized-use-only'
import { cisIdFromChatUserId, getChannelMembers } from '../helpers/stream/streamChatHelper'
import { getPortraitUrlFromCisId } from '../helpers/portraitServiceHelper'

export const getMonogramFromName = (displayName) => {
  const displayNames = (displayName?.split(',') || []).map((name) => name.trim())
  if (displayNames.length > 1) {
    return { monogram1: displayNames[0][0], monogram2: displayNames[1][0] }
  }
  if (displayNames.length === 1) {
    return { monogram1: displayNames[0][0] }
  }
  return undefined
}

export const getMonogramForVendor = (displayName) => {
  const displayNames = (displayName?.split('-') || []).map((name) => name.trim())
  if (displayNames.length > 1) {
    return { monogram1: displayNames[0][0], monogram2: displayNames[1][0] }
  }
  if (displayNames.length === 1) {
    return { monogram1: displayNames[0][0] }
  }
  return undefined
}

export const shouldDisplayMultiAvatar = ({ isGroup, isVendor, monograms }) => {
  return isGroup && !isVendor && monograms && !!monograms.monogram1 && !!monograms.monogram2
}

export const shouldDisplaySingleAvatar = ({ isGroup, monograms }) => {
  return !isGroup && monograms && !!monograms.monogram1
}

const multiAvatarComponent = ({ monograms, isInList }) => {
  return isInList ? (
    <ListItem.MultiAvatar avatar1={{ monogram: monograms?.monogram1 }} avatar2={{ monogram: monograms?.monogram2 }} />
  ) : (
    <MultiAvatar avatar1={{ monogram: monograms?.monogram1 }} avatar2={{ monogram: monograms?.monogram2 }} />
  )
}

const avatarComponent = ({ monograms, isInList, ...props }) => {
  return isInList ? (
    <ListItem.Avatar
      {...props}
      avatar1={{ monogram: monograms?.monogram1 }}
      avatar2={{ monogram: monograms?.monogram2 }}
    />
  ) : (
    <Avatar {...props} avatar1={{ monogram: monograms?.monogram1 }} avatar2={{ monogram: monograms?.monogram2 }} />
  )
}

export function chatAvatar({ name, isGroup, isVendor, src, isOnline, isInList = false }) {
  const monograms = getMonogramFromName(name)

  if (shouldDisplayMultiAvatar({ isGroup, isVendor, monograms })) {
    return multiAvatarComponent({ monograms, isInList })
  }
  if (isVendor && isGroup) {
    const vendorMonograms = getMonogramForVendor(name)
    return (
      <ListItem.MultiAvatar
        avatar1={{ monogram: vendorMonograms?.monogram1 }}
        avatar2={{ src, monogram: vendorMonograms?.monogram2 }}
      />
    )
  }
  if (isVendor && !isGroup) {
    const vendorMonograms = getMonogramForVendor(name)
    return <ListItem.Avatar monogram={vendorMonograms?.monogram2} src={src} />
  }
  if (shouldDisplaySingleAvatar({ isGroup, isVendor, monograms })) {
    return avatarComponent({ monogram: monograms?.monogram1, src, isInList, presence: isOnline ? 'online' : null })
  }

  return null
}

export const getAvatarPropsForStreamUser = (user) => {
  const cisId = cisIdFromChatUserId(user?.id)
  const src = getPortraitUrlFromCisId(cisId)
  const presence = user?.online ? 'online' : undefined
  const displayName = user?.name
  const monogram = displayName && displayName.charAt(0) ? displayName.charAt(0) : 'U'
  return { monogram, presence, src }
}

export function streamUserAvatar({ user, isInList = false, ...props }) {
  if (!user) {
    return null
  }
  const avatarProps = getAvatarPropsForStreamUser(user)
  if (isInList) {
    return <ListItem.Avatar {...avatarProps} {...props} data-testid="chat-list-item-avatar" role="status" />
  }
  return <Avatar {...avatarProps} {...props} data-testid="chat-avatar" />
}

export function getStreamChannelAvatar({ channel, excludeUserId, isInList = false, ...props }) {
  const members = getChannelMembers({ channel, excludeUserId })
  if (members.length < 1) {
    return null
  }
  if (members.length === 1) {
    return streamUserAvatar({ user: members[0]?.user, ...props, isInList })
  }
  const avatarProps1 = getAvatarPropsForStreamUser(members[0]?.user)
  const avatarProps2 = getAvatarPropsForStreamUser(members[1]?.user)
  if (isInList) {
    return (
      <ListItem.MultiAvatar
        avatar1={avatarProps1}
        avatar2={avatarProps2}
        {...props}
        data-testid="chat-list-item-multi-avatar"
      />
    )
  }
  return <MultiAvatar avatar1={avatarProps1} avatar2={avatarProps2} {...props} data-testid="chat-multi-avatar" />
}
