import axios from '@fs/zion-axios'
import { sgBaseUrl } from '@fs/zion-config'
import { getSessionId } from '@fs/zion-session'

const searchServiceUrl = '/service/user/profile/directory/users'
const connectionsEndpointUrl = '/service/user/connections/connections'
const countriesUrl = '/service/user/profile/countries'
const sgEnvUrl = sgBaseUrl || 'https://sg31b0.familysearch.org'

export async function warmUpConnectionsApi() {
  return axios.get(connectionsEndpointUrl, {
    headers: { Accept: 'application/familysearch-user-profile+v1.1+json' },
  })
}

async function getLocationDetails(locationId) {
  const reqUrl = `${countriesUrl}/${locationId}`
  return axios.get(reqUrl).then((res) => {
    return res.data
  })
}

export async function getStatesAndProvinces(countryId) {
  return getLocationDetails(countryId).then((res) => {
    return res.children
  })
}
export function removeIllegalProfileNameCharacters(str = '') {
  return str.replace(/[,!@#$^&%*;()<>[\]{}=:?~|`/"\\]/gi, '').trim()
}

export async function getMatchingPeople(
  inputText,
  countryValue,
  stateValue,
  isAdvancedSearch,
  shouldUseUserConnections
) {
  const params = {}
  const sanitizedInput = removeIllegalProfileNameCharacters(inputText || '')
  if (inputText && inputText[0] === '@') {
    inputText = inputText.substring(1)
    params.contactId = sanitizedInput
  } else {
    params.name = sanitizedInput
  }

  if (shouldUseUserConnections && !isAdvancedSearch) {
    const result = await axios.get(connectionsEndpointUrl, { params, headers: { Accept: 'application/json' } })
    return { result, fromConnectionsUrl: true }
  }

  if (isAdvancedSearch) {
    params.contactId = removeIllegalProfileNameCharacters(inputText || '')
    if (countryValue) {
      params.country = countryValue
      if (stateValue) {
        params.state = stateValue
      }
    }
  }
  const result = await axios.get(searchServiceUrl, {
    params,
    headers: { Accept: 'application/familysearch-user-profile+v1.1+json' },
  })
  return { result, fromConnectionsUrl: false }
}

export async function getCountries() {
  return axios.get(countriesUrl).then((res) => {
    return res?.data?.places || []
  })
}

// for inclusions
export async function getProfileByCisId(cisId) {
  return axios.get(`${searchServiceUrl}/${cisId}`, {
    headers: { Accept: 'application/familysearch-user-profile+v1.1+json' },
  })
}

export function getPortraitUrl(cisId) {
  return `${sgEnvUrl}/service/msg-artifact/user-portrait/${cisId}/thumb64?sessionId=${getSessionId()}`
}
