import { useCallback } from 'react'
import { useFeatureFlags } from '@fs/zion-flags'
import profileSearchLog from './profileSearchLog'

export default function useProfileSearchLog({ component } = {}) {
  const { help_profileSearchLogs } = useFeatureFlags(['help_profileSearchLogs'])
  const shouldLog = help_profileSearchLogs?.isOn

  const log = useCallback(
    ({ msg, level }) => {
      if (shouldLog) {
        profileSearchLog({ component, msg, level })
      }
    },
    [shouldLog, component]
  )

  return { log }
}
