import { i18n } from '@fs/zion-locale'
import { ListItem } from '@fs/zion-ui'
import React from 'react'
import { getStreamChannelAvatar, streamUserAvatar } from '../chat-avatar/chatAvatar'
import {
  getChannelDescription,
  getChannelName,
  isChannelBlocked,
  isUserBlocked,
  CHAT_MESSAGE_TYPE,
} from '../helpers/stream/streamChatHelper'
import { isDirectChannel } from '../services/fsChat/fsChatService'
import formatChatTimestamp from '../helpers/formatChatTimestamp'

// Gets a 75-character substring at a point where the search string is contained - for autosuggest highlighting
const truncate = (str, searchStr) => {
  const index = str.toLowerCase().indexOf(searchStr.toLowerCase())
  if (index !== -1) {
    const maxLength = 75
    const start = Math.max(0, index - Math.floor((maxLength - searchStr.length) / 2))
    const end = Math.min(index + Math.floor((maxLength - searchStr.length) / 2) + searchStr.length, str.length)
    let truncatedString = str.slice(start, end)

    if (start > 0) {
      truncatedString = `…${truncatedString}`
    }
    if (end < str.length) {
      truncatedString = `${truncatedString}…`
    }

    return truncatedString
  }
  return str.slice(0, 75)
}

/**
 * Convert roster chat items into suggestion objects to be displayed in the AutoSuggest component.
 */
export function getProfileSearchGroupSuggestions({ privateChannels, excludeUserId, client }) {
  return privateChannels
    .filter((channel) => isDirectChannel(channel) && !isChannelBlocked({ channel, client }))
    .map((channel) => ({
      key: channel.cid,
      primaryText: getChannelName({ channel, excludeUserId }),
      secondaryText: getChannelDescription(channel),
      startElement: getStreamChannelAvatar({ channel, isInList: true, excludeUserId }),
      channel,
      group: i18n.t('chat.recent-chats.label', 'Recent Chats'),
    }))
}

/**
 * Convert chat messages into suggestion objects to be displayed in the AutoSuggest component.
 */
export function mapChatMessagesToSuggestions({ messages, client, searchStr }) {
  return messages
    .filter(
      (message) => !isUserBlocked({ userId: message?.user?.id, client }) && message?.type !== CHAT_MESSAGE_TYPE.DELETED
    )
    .map((message) => ({
      key: message.id,
      primaryText: truncate(message?.text, searchStr),
      secondaryText: message?.user?.name,
      startElement: streamUserAvatar({ user: message?.user, isInList: true }),
      endElement: <ListItem.MetaText text={formatChatTimestamp(message?.created_at)} />,
      channel: message?.channel,
      message,
      group: i18n.t('chat.from-chat-messages.label', 'From Chat Messages'),
    }))
}
