import React from 'react'
import { colors, ListItem } from '@fs/zion-ui'
import { HelpAskQuestion, PersonGroup } from '@fs/zion-icon'
import { i18n } from '@fs/zion-locale'
import {
  isSessionChannel,
  isRootsTechChannel,
  isPublicChannel,
  isSupportChannel,
  isFamilySearchGroup,
} from '../services/fsChat/fsChatService'
import { CHANNEL_TYPE_ICON, CHANNEL_TYPE } from '../services/fsChat/fsChannelEnums'
import { chatAvatar } from '../chat-avatar/chatAvatar'
import { getChannelName } from '../helpers/stream/streamChatHelper'

const getGroupLabel = (channel) => {
  if (isSupportChannel(channel)) {
    return i18n.t('chat.ask-us-anything.heading', 'Ask Us Anything - RootsTech')
  }
  if (isPublicChannel(channel)) {
    return i18n.t('chat.attendee-groups.heading', 'Attendee Created')
  }
  if (isSessionChannel(channel)) {
    return i18n.t('chat.session.heading', 'Session Chats - RootsTech')
  }
  if (isRootsTechChannel(channel)) {
    return i18n.t('chat.rootstech-groups.heading', 'RootsTech Groups')
  }
  if (isFamilySearchGroup(channel)) {
    return i18n.t('chat.familysearch-groups.heading', 'Family Groups')
  }

  return i18n.t('chat.other-groups.heading', 'Other Chats')
}

const truncate = (str) => {
  return str?.length > 75 ? `${str.substring(0, 75)}...` : str
}

function getStartElement(channel) {
  switch (channel?.type) {
    case CHANNEL_TYPE.FS_SUPPORT:
      return <ListItem.Icon Icon={HelpAskQuestion} color={colors.blue30} />
    case CHANNEL_TYPE.FS_VENDOR:
      return chatAvatar({
        isInList: true,
        isVendor: true,
        isGroup: true,
        src: channel?.data?.image,
        name: getChannelName({ channel }),
      })
    default:
      return <ListItem.Icon Icon={CHANNEL_TYPE_ICON[channel?.type] || PersonGroup} />
  }
}

/**
 * Convert a list of chat channels to a list specifically designed for the auto-suggest component.
 *
 * @param {Array} chatGroups The list of chat groups
 * @param {string} group overrides default group heading.
 * @returns A list for auto-suggest
 */
export default function mapChatGroupsToSuggestion({ chatGroups, group }) {
  return chatGroups?.map((channel) => {
    const secondaryText = truncate(channel.data?.description)

    return {
      key: channel?.cid,
      primaryText: getChannelName({ channel }),
      secondaryText,
      startElement: getStartElement(channel),
      channel,
      group: group || getGroupLabel(channel),
    }
  })
}
