import React, { createContext, useContext, useMemo, useState } from 'react'
import { useCountries } from './profileSearchHooks'

const ProfileContext = createContext({})

export default function ProfileSearchProvider({
  children,
  onSuggestionSelected = () => {},
  exclusionList = null,
  inclusions = null,
  removeAdvancedSearch = false,
  onInputTextChange,
  selectedItem,
  disabled = false,
  label,
  clearInputOnSelection = false,
  onClear = () => {},
  onBlur = () => {},
  placeholder = '',
  hideMessaging,
  optInUrl,
  promptOptIn,
  shouldUseUserConnections,
}) {
  const [contactSelected, setContactSelected] = useState({ cisId: '' })
  const [countryValue, setCountryValue] = useState('')
  const [stateValue, setStateValue] = useState('')
  const [error, setError] = useState(false)
  const [suggestionResults, setSuggestionResults] = useState([])
  const [isLoadingSuggestions, setIsLoadingSuggestions] = useState(false)
  const [countryOptions] = useCountries()
  const [countryStateMapping, setCountryStateMapping] = useState({})

  const state = useMemo(
    () => ({
      onSuggestionSelected,
      exclusionList,
      inclusions,
      removeAdvancedSearch,
      onInputTextChange,
      selectedItem,
      disabled,
      label,
      clearInputOnSelection,
      onClear,
      onBlur,
      placeholder,
      contactSelected,
      setContactSelected,
      countryValue,
      setCountryValue,
      stateValue,
      setStateValue,
      error,
      setError,
      suggestionResults,
      setSuggestionResults,
      isLoadingSuggestions,
      setIsLoadingSuggestions,
      countryOptions,
      hideMessaging,
      optInUrl,
      promptOptIn,
      shouldUseUserConnections,
      countryStateMapping,
      setCountryStateMapping,
    }),
    [
      clearInputOnSelection,
      contactSelected,
      countryOptions,
      countryStateMapping,
      countryValue,
      disabled,
      error,
      exclusionList,
      hideMessaging,
      inclusions,
      isLoadingSuggestions,
      label,
      onBlur,
      onClear,
      onInputTextChange,
      onSuggestionSelected,
      optInUrl,
      placeholder,
      promptOptIn,
      removeAdvancedSearch,
      selectedItem,
      shouldUseUserConnections,
      stateValue,
      suggestionResults,
    ]
  )

  return <ProfileContext.Provider value={state}> {children} </ProfileContext.Provider>
}

export const useProfileContext = () => {
  const state = useContext(ProfileContext)
  if (!state) {
    throw new Error('useProfileContext called outside ProfileProvider')
  }
  return state
}
