import { getSessionId } from '@fs/zion-session'
import { sgEnvUrl } from '../global/chatConfig'
import { cisIdFromChatUserId, getChannelMembers } from './stream/streamChatHelper'

export function getPortraitUrlFromCisId(cisId) {
  if (!cisId) {
    return ''
  }

  return `${sgEnvUrl}/service/msg-artifact/user-portrait/${cisId}/thumb64?sessionId=${getSessionId()}`
}

export function portraitURLFromUser(user) {
  return getPortraitUrlFromCisId(cisIdFromChatUserId(user?.id))
}

export function getPortraitUrlFromChannel({ channel, excludeUserId }) {
  const members = getChannelMembers({ channel, excludeUserId })
  if (members.length === 1) {
    return getPortraitUrlFromCisId(cisIdFromChatUserId(members[0].user_id))
  }
  return null
}
