import React from 'react'
import { useTranslation } from 'react-i18next'
import ProfileSearch from '@fs/zion-profile-search'
import { css } from '@linaria/core'
import { baseUrl } from '@fs/zion-config'
import useChatInviteProfileSearch from '../hooks/useChatInviteProfileSearch'
import { removeIllegalProfileNameCharacters } from '../services/userProfile/userProfileService'
import { MAX_STREAM_SEARCH_LENGTH } from '../hooks/useChatSearchChats'

const profileTextFieldCss = css`
  overflow: scroll;

  /* Prevent scrollbars from showing when user has "show scrollbars always" on */
  scrollbar-width: none;
  -ms-overflow-style: none;
  &::-webkit-scrollbar {
    display: none;
  }
`

export default function ChatInviteProfileSearch({
  label,
  disabled,
  excludedUsers = [],
  onClickSuggestion = () => {},
  openAutosuggestByDefault = false,
}) {
  const [t] = useTranslation()
  const { setInputText, exclusionList, focusRef, inclusions } = useChatInviteProfileSearch(
    excludedUsers,
    openAutosuggestByDefault
  )
  return (
    <div className={profileTextFieldCss}>
      <ProfileSearch
        label={label}
        clearInputOnSelection
        clearable
        data-testid="chat-invite-profile-search"
        disabled={disabled}
        exclusionList={Array.isArray(exclusionList) ? exclusionList : [exclusionList]}
        hideMessaging
        inclusions={inclusions}
        onInputTextChange={(text) => {
          setInputText(removeIllegalProfileNameCharacters(text))
        }}
        onSuggestionSelected={onClickSuggestion}
        placeholder={t('chat.to.placeholder', 'Kim Lee, @KimLee123, etc.')}
        promptOptIn
        optInUrl={`${baseUrl || window.location.origin}/help/helper/profile-opt-in`}
        ref={focusRef}
        maxLength={MAX_STREAM_SEARCH_LENGTH}
        selectedItem={null}
        shouldUseUserConnections
      />
    </div>
  )
}
