import { splunk } from '@fs/zion-splunk-logger'
import zionDebug from '@fs/zion-debug'

export const LOG_LEVEL = {
  LOG: 1,
  INFO: 2,
  WARN: 3,
  ERROR: 4,
}

const debug = zionDebug('zion:profile-search:log')
export default function profileSearchLog({ component, msg, level }) {
  debug(`${component} ${msg}`)
  const splunkParams = { component: `[profileSearch]${component}`, msg }

  switch (level) {
    case LOG_LEVEL.LOG:
    case LOG_LEVEL.INFO: {
      splunk.log(splunkParams)
      break
    }
    case LOG_LEVEL.WARN: {
      splunk.warn(splunkParams)
      break
    }
    case LOG_LEVEL.ERROR: {
      const obj = {}
      // captureStackTrace is a non-standard V8 function in Chromium-based browsers
      Error?.captureStackTrace?.(obj, profileSearchLog)
      splunkParams.stack = obj.stack
      splunk.error(splunkParams)
      break
    }
    default: {
      splunk.log(`[ProfileSearch] ${msg}`)
      break
    }
  }
}
